def get_indian_time():
    """Get current time in IST timezone"""
    ist = pytz.timezone('Asia/Kolkata')
    return datetime.now(ist)


# Case-insensitive role check - all stored in lowercase for comparison
ACCOUNTS_ALLOWED_ROLES = {'vgk4u', 'ea', 'accounts', 'executive_assistant', 'executive assistant', 'senior_executive', 'key_leadership'}

def is_accounts_allowed_role(role_code: str) -> bool:
    """Case-insensitive check if role is allowed for accounts operations"""
    if not role_code:
        return False
    return role_code.lower().strip() in ACCOUNTS_ALLOWED_ROLES


def is_accounts_supreme_employee(employee) -> bool:
    """
    DC Protocol (May 2026, Task #47): Identify employees with company-wide unrestricted access.
    Per the user-stated rule: "VGK mentor, EA and Accounts department staff have complete access".
    All other employees are constrained to their `data_companies` selection (set on the Employee
    Create/Edit page). This helper is the single decision point for that bypass.
    DC-ACCT-ACCESS-001 (May 2026): MR10001 (VGK4U Mentor) and any employee with MENTOR
    in their designation always have supreme access regardless of role/department.
    """
    if not employee:
        return False
    role_code = (getattr(getattr(employee, 'role', None), 'role_code', '') or '').lower().strip()
    if role_code in ('vgk4u', 'ea', 'executive_assistant', 'executive assistant', 'accounts', 'key_leadership'):
        return True
    # DC-ACCT-ACCESS-001: MR10001 (VGK4U Mentor) always has supreme access
    if getattr(employee, 'emp_code', '') == 'MR10001':
        return True
    # DC-ACCT-ACCESS-001: Any MENTOR designation has supreme access
    if 'MENTOR' in (getattr(employee, 'designation', '') or '').upper():
        return True
    # Primary department named like Accounts/Finance
    primary_dept = getattr(employee, 'department', None)
    if primary_dept:
        pd_name = (getattr(primary_dept, 'name', '') or '').lower()
        if 'accounts' in pd_name or 'finance' in pd_name:
            return True
    # Additional departments mapped as Accounts/Finance
    for ad in getattr(employee, 'additional_departments', []) or []:
        ad_dept = getattr(ad, 'department', None)
        if ad_dept:
            ad_name = (getattr(ad_dept, 'name', '') or '').lower()
            if 'accounts' in ad_name or 'finance' in ad_name:
                return True
    return False


def get_employee_data_company_ids(employee) -> Optional[List[int]]:
    """
    DC Protocol (May 2026, Task #47): Read the employee's associated companies from
    `StaffEmployee.data_companies` (JSONB list of company IDs, set on the Employee page).
    Returns:
        - None  → employee is supreme (VGK/EA/Accounts dept) → no restriction
        - []    → employee has no companies assigned → must see no company-level data
        - [ids] → restricted to this set of company IDs
    """
    if is_accounts_supreme_employee(employee):
        return None
    raw = getattr(employee, 'data_companies', None) or []
    out: List[int] = []
    if isinstance(raw, (list, tuple)):
        for v in raw:
            try:
                out.append(int(v))
            except (TypeError, ValueError):
                continue
    return out


def is_accounts_allowed_employee(employee) -> bool:
    """
    DC Protocol (Mar 09, 2026): Check accounts access via primary role OR additional departments.
    An employee is allowed if their primary role_code is in ACCOUNTS_ALLOWED_ROLES,
    OR if any of their additional departments is Accounts/Finance/Store.
    DC Protocol (Apr 2026): Added 'store' — Store dept staff manage PO/PR/invoices.
    DC-ACCT-ACCESS-001 (May 2026): MR10001 (VGK4U Mentor) and MENTOR designation always
    allowed. Primary department Accounts/Finance also grants access (not just additional depts).
    This is the single source of truth for all accounts access checks.
    """
    if not employee or not employee.role:
        return False
    if is_accounts_allowed_role(employee.role.role_code):
        return True
    # DC-ACCT-ACCESS-001: MR10001 (VGK4U Mentor) always has full accounts access
    if getattr(employee, 'emp_code', '') == 'MR10001':
        return True
    # DC-ACCT-ACCESS-001: Any MENTOR designation grants full accounts access
    if 'MENTOR' in (getattr(employee, 'designation', '') or '').upper():
        return True
    # DC-ACCT-ACCESS-001: Primary department = Accounts/Finance grants access
    primary_dept = getattr(employee, 'department', None)
    if primary_dept:
        pd_name = (getattr(primary_dept, 'name', '') or '').lower()
        if 'accounts' in pd_name or 'finance' in pd_name:
            return True
    # Additional departments = Accounts/Finance/Store
    for ad in getattr(employee, 'additional_departments', []):
        ad_dept = getattr(ad, 'department', None)
        if ad_dept:
            ad_name = (getattr(ad_dept, 'name', '') or '').lower()
            if 'accounts' in ad_name or 'finance' in ad_name or 'store' in ad_name:
                return True
    return False


class AccountsRBACError(Exception):
    """Raised when user doesn't have permission for accounts operations"""
    pass


class AccountsValidationError(Exception):
    """Raised when validation fails"""
    pass


class AccountsNotFoundError(Exception):
    """Raised when requested resource is not found"""
    pass


class AccountsDuplicateError(Exception):
    """Raised when duplicate entry is detected"""
    pass


def validate_accounts_access(employee: StaffEmployee) -> bool:
    """
    Validate if employee has access to accounts module.
    DC Protocol (Mar 09, 2026): Checks primary role AND additional departments.
    VGK and EA have equal full permissions. Additional Accounts dept also grants access.
    DC Protocol (May 2026): WRITE/mutation guard — use validate_accounts_read_access for GET/list.
    """
    if not employee or not employee.role:
        raise AccountsRBACError("Employee role not found")
    if not is_accounts_allowed_employee(employee):
        raise AccountsRBACError(
            f"Access denied. Only VGK4U, EA, and Accounts roles can access financial management. "
            f"Your role: {employee.role.role_name}"
        )
    return True


def validate_accounts_read_access(employee: StaffEmployee) -> bool:
    """
    DC Protocol (May 2026): Option B RBAC split.
    READ-ONLY guard — any authenticated, active staff member may browse master data
    (companies, vendors, stock items, segments, purchase invoices, HSN codes, etc.).
    Authentication (JWT) is already enforced by get_current_staff_user dependency.
    Write/mutation operations must still use validate_accounts_access().
    """
    if not employee:
        raise AccountsRBACError("Authenticated employee not found")
    if getattr(employee, 'status', 'active') not in ('active', 'Active', 'ACTIVE'):
        raise AccountsRBACError("Your account is inactive. Contact HR.")
    return True


def log_accounts_audit(
    db: Session,
    employee_id: int,
    action: str,
    entity_type: str,
    entity_id: int,
    old_values: Optional[Dict] = None,
    new_values: Optional[Dict] = None,
    description: str = ""
):
    """Log audit trail for accounts operations"""
    log_staff_audit(
        db=db,
        employee_id=employee_id,
        action=f"ACCOUNTS_{action}",
        resource_type=entity_type,
        resource_id=entity_id,
        old_data=old_values,
        new_data=new_values
    )


# ==================== ASSOCIATED COMPANIES SERVICE ====================

class AssociatedCompanyService:
    """Service layer for Associated Companies management"""
    
    @staticmethod
    def create_company(
        db: Session,
        data: AssociatedCompanyCreate,
        employee: StaffEmployee
    ) -> AssociatedCompany:
        """Create a new associated company"""
        validate_accounts_access(employee)
        
        existing = db.query(AssociatedCompany).filter(
            or_(
                func.lower(AssociatedCompany.company_code) == data.company_code.lower(),
                func.lower(AssociatedCompany.company_name) == data.company_name.lower().strip()
            )
        ).first()
        
        if existing:
            if existing.company_code.lower() == data.company_code.lower():
                raise AccountsDuplicateError(f"Company code '{data.company_code}' already exists")
            raise AccountsDuplicateError(f"Company name '{data.company_name}' already exists")
        
        if data.is_book_keeper:
            existing_keeper = db.query(AssociatedCompany).filter(
                AssociatedCompany.is_book_keeper == True
            ).first()
            if existing_keeper:
                raise AccountsValidationError(
                    f"Book keeper already exists: {existing_keeper.company_name}. "
                    "Only one company can be the book keeper."
                )
        
        company = AssociatedCompany(
            company_name=data.company_name.strip(),
            company_code=data.company_code.upper().strip(),
            company_type=data.company_type,
            gst_number=data.gst_number,
            pan_number=data.pan_number,
            cin_number=data.cin_number,
            address=data.address,
            city=data.city,
            state=data.state,
            pincode=data.pincode,
            bank_name=data.bank_name,
            bank_branch=data.bank_branch,
            account_number=data.account_number,
            ifsc_code=data.ifsc_code,
            account_type=data.account_type,
            upi_id=data.upi_id,
            is_book_keeper=data.is_book_keeper,
            is_marketplace_endpoint=getattr(data, 'is_marketplace_endpoint', False) or False,
            is_active=data.is_active,
            created_by_id=employee.id
        )
        
        db.add(company)
        db.commit()
        db.refresh(company)
        
        log_accounts_audit(
            db=db,
            employee_id=employee.id,
            action="CREATE_COMPANY",
            entity_type="AssociatedCompany",
            entity_id=company.id,
            new_values={"company_code": company.company_code, "company_name": company.company_name},
            description=f"Created company: {company.company_name} ({company.company_code})"
        )
        
        # DC_SFMS_SEED_002 (May 2026): Auto-seed defaults for the new company.
        # Wrapped in try/except so company creation never fails due to seed issues.
        # Idempotent — safe even if a partial run already happened.
        try:
            from app.services.sfms_seed import seed_company_full_defaults
            _seed_summary = seed_company_full_defaults(db, company.id, employee.id)
            logging.info(f"[DC_SFMS_SEED_002] Auto-seeded new company {company.id} ({company.company_name}): {_seed_summary}")
        except Exception as _seed_err:
            logging.warning(f"[DC_SFMS_SEED_002] Auto-seed for new company {company.id} failed (non-fatal): {_seed_err}")
        
        return company
    
    @staticmethod
    def get_company(db: Session, company_id: int, employee: StaffEmployee) -> AssociatedCompany:
        """Get a single associated company by ID"""
        validate_accounts_read_access(employee)
        
        company = db.query(AssociatedCompany).filter(
            AssociatedCompany.id == company_id
        ).first()
        
        if not company:
            raise AccountsNotFoundError(f"Company with ID {company_id} not found")
        
        return company
    
    @staticmethod
    def list_companies(
        db: Session,
        employee: StaffEmployee,
        page: int = 1,
        page_size: int = 20,
        status_filter: Optional[str] = None,
        search: Optional[str] = None
    ) -> Tuple[List[AssociatedCompany], int]:
        """List all associated companies with pagination and filters.
        DC Protocol (May 2026, Task #47): Non-supreme employees only see companies in their
        `data_companies` selection. VGK / EA / Accounts dept (supreme) see everything.
        """
        validate_accounts_read_access(employee)
        
        query = db.query(AssociatedCompany)

        # Restrict to employee's associated companies (unless supreme)
        allowed_ids = get_employee_data_company_ids(employee)
        if allowed_ids is not None:
            if not allowed_ids:
                return [], 0
            query = query.filter(AssociatedCompany.id.in_(allowed_ids))

        # DC-CO-FILTER-001: Default to active-only so inactive/deleted companies
        # are hidden everywhere (dropdowns, reports, ledgers, banks, etc.).
        # Pass status_filter='ALL' explicitly to see inactive companies (admin use only).
        if status_filter and status_filter.upper() == 'ALL':
            pass  # no is_active filter — show everything
        elif status_filter and status_filter.upper() == 'INACTIVE':
            query = query.filter(AssociatedCompany.is_active == False)
        else:
            # Default: active only (covers status_filter='ACTIVE' or None)
            query = query.filter(AssociatedCompany.is_active == True)
        
        if search:
            search_term = f"%{search.strip()}%"
            query = query.filter(
                or_(
                    AssociatedCompany.company_name.ilike(search_term),
                    AssociatedCompany.company_code.ilike(search_term),
                    AssociatedCompany.city.ilike(search_term)
                )
            )
        
        total = query.count()
        
        companies = query.order_by(
            desc(AssociatedCompany.is_book_keeper),
            AssociatedCompany.company_name
        ).offset((page - 1) * page_size).limit(page_size).all()
        
        return companies, total
    
    @staticmethod
    def update_company(
        db: Session,
        company_id: int,
        data: AssociatedCompanyUpdate,
        employee: StaffEmployee
    ) -> AssociatedCompany:
        """Update an associated company"""
        validate_accounts_access(employee)
        
        company = db.query(AssociatedCompany).filter(
            AssociatedCompany.id == company_id
        ).first()
        
        if not company:
            raise AccountsNotFoundError(f"Company with ID {company_id} not found")
        
        old_values = {
            "company_name": company.company_name,
            "is_active": company.is_active
        }
        
        update_data = data.model_dump(exclude_unset=True)
        
        if 'company_name' in update_data:
            existing = db.query(AssociatedCompany).filter(
                AssociatedCompany.id != company_id,
                func.lower(AssociatedCompany.company_name) == update_data['company_name'].lower().strip()
            ).first()
            if existing:
                raise AccountsDuplicateError(f"Company name '{update_data['company_name']}' already exists")
        
        if 'is_active' in update_data and company.is_book_keeper and update_data['is_active'] == False:
            raise AccountsValidationError(
                "Cannot deactivate the book keeper company. "
                "Assign another company as book keeper first."
            )
        
        for field, value in update_data.items():
            if hasattr(company, field):
                setattr(company, field, value)
        
        company.updated_by_id = employee.id  # DC Protocol audit trail
        company.updated_at = get_indian_time()
        
        db.commit()
        db.refresh(company)
        
        log_accounts_audit(
            db=db,
            employee_id=employee.id,
            action="UPDATE_COMPANY",
            entity_type="AssociatedCompany",
            entity_id=company.id,
            old_values=old_values,
            new_values={"company_name": company.company_name, "is_active": company.is_active},
            description=f"Updated company: {company.company_name}"
        )
        
        return company
    
    @staticmethod
    def delete_company(
        db: Session,
        company_id: int,
        employee: StaffEmployee
    ) -> bool:
        """Soft delete (deactivate) an associated company"""
        validate_accounts_access(employee)
        
        company = db.query(AssociatedCompany).filter(
            AssociatedCompany.id == company_id
        ).first()
        
        if not company:
            raise AccountsNotFoundError(f"Company with ID {company_id} not found")
        
        if company.is_book_keeper:
            raise AccountsValidationError(
                "Cannot delete the book keeper company. "
                "Assign another company as book keeper first."
            )
        
        has_segments = db.query(CompanySegment).filter(
            CompanySegment.company_id == company_id,
            CompanySegment.is_active == True
        ).count() > 0
        
        if has_segments:
            raise AccountsValidationError(
                "Cannot delete company with active segments. "
                "Deactivate or reassign segments first."
            )
        
        company.is_active = False
        company.updated_by_id = employee.id  # DC Protocol audit trail
        company.updated_at = get_indian_time()
        
        db.commit()
        
        log_accounts_audit(
            db=db,
            employee_id=employee.id,
            action="DELETE_COMPANY",
            entity_type="AssociatedCompany",
            entity_id=company.id,
            old_values={"is_active": True},
            new_values={"is_active": False},
            description=f"Deactivated company: {company.company_name}"
        )
        
        return True
    
    # ── DC-CO-TRANSFER-001 ──────────────────────────────────────────────────
    # Tables we allow bulk-transfer of company_id when merging a duplicate.
    # Deliberately excludes: CRM, payroll, staff employees, call-tracking,
    # journey, VGK wallet — those have their own ownership semantics.
    _TRANSFER_TABLES = [
        ("company_segments",          "company_id",  "Business Segments"),
        ("income_entries",             "company_id",  "Income Entries"),
        ("expense_entries",            "company_id",  "Expense Entries"),
        ("journal_vouchers",           "company_id",  "Journal Vouchers"),
        ("account_ledger",             "company_id",  "General Ledger Entries"),
        ("account_ledger_masters",     "company_id",  "Ledger Accounts"),
        ("party_ledger",               "company_id",  "Party Ledger"),
        ("purchase_invoice_uploads",   "company_id",  "Purchase Invoices"),
        ("sales_invoices",             "company_id",  "Sales Invoices"),
        ("stock_item_master",          "company_id",  "Stock Items"),
        ("company_bank_accounts",      "company_id",  "Bank Accounts"),
    ]

    @staticmethod
    def get_company_transfer_summary(
        db: Session,
        company_id: int,
        employee: StaffEmployee
    ) -> list:
        """DC-CO-TRANSFER-001: Return count of all transferable data for a company."""
        validate_accounts_access(employee)
        company = db.query(AssociatedCompany).filter(AssociatedCompany.id == company_id).first()
        if not company:
            raise AccountsNotFoundError(f"Company {company_id} not found")

        summary = []
        for table, col, label in AssociatedCompanyService._TRANSFER_TABLES:
            try:
                count = db.execute(
                    text(f"SELECT COUNT(*) FROM {table} WHERE {col} = :cid"),
                    {"cid": company_id}
                ).scalar() or 0
                if count > 0:
                    summary.append({"table": table, "label": label, "count": int(count)})
            except Exception:
                pass
        return summary

    @staticmethod
    def transfer_company_data(
        db: Session,
        source_id: int,
        target_id: int,
        employee: StaffEmployee
    ) -> dict:
        """DC-CO-TRANSFER-001: Transfer all data from source company to target, then deactivate source."""
        validate_accounts_access(employee)

        if source_id == target_id:
            raise AccountsValidationError("Source and target company must be different.")

        source = db.query(AssociatedCompany).filter(AssociatedCompany.id == source_id).first()
        target = db.query(AssociatedCompany).filter(AssociatedCompany.id == target_id).first()

        if not source:
            raise AccountsNotFoundError(f"Source company {source_id} not found")
        if not target:
            raise AccountsNotFoundError(f"Target company {target_id} not found")
        if not target.is_active:
            raise AccountsValidationError("Target company is inactive.")

        # Auto-reassign book keeper role to target when source is the book keeper
        book_keeper_reassigned = False
        if source.is_book_keeper:
            # Use direct ORM attribute updates (not bulk .update()) so the session
            # identity map stays consistent and no InFailedSqlTransaction occurs.
            source.is_book_keeper = False
            source.updated_at = get_indian_time()
            target.is_book_keeper = True
            target.updated_at = get_indian_time()
            db.flush()  # Persist reassignment cleanly before the audit INSERT
            book_keeper_reassigned = True
            log_accounts_audit(
                db=db,
                employee_id=employee.id,
                action="SET_BOOK_KEEPER",
                entity_type="AssociatedCompany",
                entity_id=target.id,
                old_values={"is_book_keeper": False},
                new_values={"is_book_keeper": True},
                description=f"Book keeper role auto-reassigned from '{source.company_name}' → '{target.company_name}' during transfer"
            )

        transferred = {}
        skipped = {}
        for table, col, label in AssociatedCompanyService._TRANSFER_TABLES:
            # Use a savepoint per table so a constraint violation on one table
            # rolls back only that statement and leaves the outer transaction healthy.
            sp = db.begin_nested()
            try:
                result = db.execute(
                    text(f"UPDATE {table} SET {col} = :target WHERE {col} = :source"),
                    {"target": target_id, "source": source_id}
                )
                sp.commit()
                if result.rowcount > 0:
                    transferred[label] = result.rowcount
            except Exception as exc:
                sp.rollback()
                skipped[label] = str(exc).splitlines()[0]
                logger.warning(f"[DC-CO-TRANSFER-001] Skipped {table}: {exc}")

        # Deactivate source company
        source.is_active = False
        source.updated_by_id = employee.id
        source.updated_at = get_indian_time()
        db.commit()

        log_accounts_audit(
            db=db,
            employee_id=employee.id,
            action="TRANSFER_COMPANY_DATA",
            entity_type="AssociatedCompany",
            entity_id=source.id,
            old_values={"is_active": True},
            new_values={"is_active": False, "transferred_to": target_id},
            description=f"Transferred data from '{source.company_name}' → '{target.company_name}' then deactivated"
        )

        return {
            "source": source.company_name,
            "target": target.company_name,
            "transferred": transferred,
            "skipped": skipped,
            "book_keeper_reassigned": book_keeper_reassigned,
        }

    @staticmethod
    def set_book_keeper(
        db: Session,
        company_id: int,
        employee: StaffEmployee
    ) -> AssociatedCompany:
        """Set a company as the book keeper (Mynt Real LLP)"""
        validate_accounts_access(employee)
        
        company = db.query(AssociatedCompany).filter(
            AssociatedCompany.id == company_id
        ).first()
        
        if not company:
            raise AccountsNotFoundError(f"Company with ID {company_id} not found")
        
        if not company.is_active:
            raise AccountsValidationError("Only active companies can be set as book keeper")
        
        db.query(AssociatedCompany).filter(
            AssociatedCompany.is_book_keeper == True
        ).update({"is_book_keeper": False, "updated_at": get_indian_time()})
        
        company.is_book_keeper = True
        company.updated_by_id = employee.id  # DC Protocol audit trail
        company.updated_at = get_indian_time()
        
        db.commit()
        db.refresh(company)
        
        log_accounts_audit(
            db=db,
            employee_id=employee.id,
            action="SET_BOOK_KEEPER",
            entity_type="AssociatedCompany",
            entity_id=company.id,
            new_values={"is_book_keeper": True},
            description=f"Set as book keeper: {company.company_name}"
        )
        
        return company


# ==================== COMPANY SEGMENTS SERVICE ====================

class CompanySegmentService:
    """Service layer for Company Segments management"""
    
    @staticmethod
    def create_segment(
        db: Session,
        data: CompanySegmentCreate,
        employee: StaffEmployee
    ) -> CompanySegment:
        """Create a new company segment"""
        validate_accounts_access(employee)
        
        company = db.query(AssociatedCompany).filter(
            AssociatedCompany.id == data.company_id
        ).first()
        
        if not company:
            raise AccountsNotFoundError(f"Company with ID {data.company_id} not found")
        
        existing = db.query(CompanySegment).filter(
            CompanySegment.company_id == data.company_id,
            or_(
                func.lower(CompanySegment.segment_code) == data.segment_code.lower(),
                func.lower(CompanySegment.segment_name) == data.segment_name.lower().strip()
            )
        ).first()
        
        if existing:
            if existing.segment_code.lower() == data.segment_code.lower():
                raise AccountsDuplicateError(
                    f"Segment code '{data.segment_code}' already exists for this company"
                )
            raise AccountsDuplicateError(
                f"Segment name '{data.segment_name}' already exists for this company"
            )
        
        segment = CompanySegment(
            company_id=data.company_id,
            segment_name=data.segment_name.strip(),
            segment_code=data.segment_code.upper().strip(),
            description=data.description,
            display_order=data.display_order,
            is_active=data.is_active,
            created_by_id=employee.id
        )
        
        db.add(segment)
        db.commit()
        db.refresh(segment)
        
        log_accounts_audit(
            db=db,
            employee_id=employee.id,
            action="CREATE_SEGMENT",
            entity_type="CompanySegment",
            entity_id=segment.id,
            new_values={"segment_code": segment.segment_code, "company_id": segment.company_id},
            description=f"Created segment: {segment.segment_name} for {company.company_name}"
        )
        
        return segment
    
    @staticmethod
    def get_segment(db: Session, segment_id: int, employee: StaffEmployee) -> CompanySegment:
        """Get a single company segment by ID"""
        validate_accounts_read_access(employee)
        
        segment = db.query(CompanySegment).filter(
            CompanySegment.id == segment_id
        ).first()
        
        if not segment:
            raise AccountsNotFoundError(f"Segment with ID {segment_id} not found")
        
        return segment
    
    @staticmethod
    def list_segments(
        db: Session,
        employee: StaffEmployee,
        company_id: Optional[int] = None,
        status_filter: Optional[str] = None
    ) -> Tuple[List[CompanySegment], int]:
        """List company segments with filters"""
        validate_accounts_read_access(employee)
        
        query = db.query(CompanySegment)
        
        if company_id:
            query = query.filter(CompanySegment.company_id == company_id)
        
        if status_filter:
            if status_filter.upper() == 'ACTIVE':
                query = query.filter(CompanySegment.is_active == True)
            elif status_filter.upper() == 'INACTIVE':
                query = query.filter(CompanySegment.is_active == False)
        
        total = query.count()
        
        segments = query.order_by(
            CompanySegment.company_id,
            CompanySegment.display_order,
            CompanySegment.segment_name
        ).all()
        
        return segments, total
    
    @staticmethod
    def update_segment(
        db: Session,
        segment_id: int,
        data: CompanySegmentUpdate,
        employee: StaffEmployee
    ) -> CompanySegment:
        """Update a company segment"""
        validate_accounts_access(employee)
        
        segment = db.query(CompanySegment).filter(
            CompanySegment.id == segment_id
        ).first()
        
        if not segment:
            raise AccountsNotFoundError(f"Segment with ID {segment_id} not found")
        
        old_values = {"segment_name": segment.segment_name, "is_active": segment.is_active}
        
        update_data = data.model_dump(exclude_unset=True)
        
        if 'segment_name' in update_data:
            existing = db.query(CompanySegment).filter(
                CompanySegment.id != segment_id,
                CompanySegment.company_id == segment.company_id,
                func.lower(CompanySegment.segment_name) == update_data['segment_name'].lower().strip()
            ).first()
            if existing:
                raise AccountsDuplicateError(
                    f"Segment name '{update_data['segment_name']}' already exists for this company"
                )
        
        for field, value in update_data.items():
            if hasattr(segment, field):
                if field == 'status' and hasattr(value, 'value'):
                    value = value.value
                setattr(segment, field, value)
        
        segment.updated_by_id = employee.id  # DC Protocol audit trail
        segment.updated_at = get_indian_time()
        
        db.commit()
        db.refresh(segment)
        
        log_accounts_audit(
            db=db,
            employee_id=employee.id,
            action="UPDATE_SEGMENT",
            entity_type="CompanySegment",
            entity_id=segment.id,
            old_values=old_values,
            new_values={"segment_name": segment.segment_name, "is_active": segment.is_active},
            description=f"Updated segment: {segment.segment_name}"
        )
        
        return segment


