# ==================== PRICING CONFIGURATION SERVICE ====================

class PricingConfigurationService:
    """Service layer for Pricing Configuration management"""
    
    @staticmethod
    def get_or_create_config(
        db: Session,
        company_id: int,
        employee: StaffEmployee
    ) -> PricingConfiguration:
        """Get existing config or create default for company"""
        validate_accounts_access(employee)
        
        company = db.query(AssociatedCompany).filter(
            AssociatedCompany.id == company_id
        ).first()
        
        if not company:
            raise AccountsNotFoundError(f"Company with ID {company_id} not found")
        
        config = db.query(PricingConfiguration).filter(
            PricingConfiguration.company_id == company_id,
            PricingConfiguration.is_active == True
        ).first()
        
        if not config:
            config = PricingConfiguration(
                company_id=company_id,
                config_type="SERVICE_ITEM_MARKUP",
                default_markup_pct=Decimal("20.00"),
                incentive_pct=Decimal("50.00"),
                min_markup_pct=Decimal("0.00"),
                is_active=True,
                configured_by_id=employee.id
            )
            db.add(config)
            db.commit()
            db.refresh(config)
            
            log_accounts_audit(
                db=db,
                employee_id=employee.id,
                action="CREATE_PRICING_CONFIG",
                entity_type="PricingConfiguration",
                entity_id=config.id,
                new_values={"company_id": company_id, "default_markup_pct": "20.00"},
                description=f"Created default pricing config for {company.company_name}"
            )
        
        return config
    
    @staticmethod
    def update_config(
        db: Session,
        config_id: int,
        data: PricingConfigurationUpdate,
        employee: StaffEmployee
    ) -> PricingConfiguration:
        """Update pricing configuration"""
        validate_accounts_access(employee)
        
        config = db.query(PricingConfiguration).filter(
            PricingConfiguration.id == config_id
        ).first()
        
        if not config:
            raise AccountsNotFoundError(f"Pricing config with ID {config_id} not found")
        
        old_values = {
            "default_markup_pct": str(config.default_markup_pct),
            "incentive_pct": str(config.incentive_pct)
        }
        
        update_data = data.model_dump(exclude_unset=True)
        
        if 'min_markup_pct' in update_data and 'default_markup_pct' in update_data:
            if update_data['min_markup_pct'] > update_data['default_markup_pct']:
                raise AccountsValidationError("Minimum markup cannot exceed default markup")
        elif 'min_markup_pct' in update_data:
            if update_data['min_markup_pct'] > config.default_markup_pct:
                raise AccountsValidationError("Minimum markup cannot exceed default markup")
        elif 'default_markup_pct' in update_data:
            if config.min_markup_pct > update_data['default_markup_pct']:
                raise AccountsValidationError("Default markup cannot be less than minimum markup")
        
        for field, value in update_data.items():
            if hasattr(config, field):
                setattr(config, field, value)
        
        config.updated_by_id = employee.id  # DC Protocol audit trail
        config.updated_at = get_indian_time()
        
        db.commit()
        db.refresh(config)
        
        log_accounts_audit(
            db=db,
            employee_id=employee.id,
            action="UPDATE_PRICING_CONFIG",
            entity_type="PricingConfiguration",
            entity_id=config.id,
            old_values=old_values,
            new_values={
                "default_markup_pct": str(config.default_markup_pct),
                "incentive_pct": str(config.incentive_pct)
            },
            description=f"Updated pricing config for company ID {config.company_id}"
        )
        
        return config
    
    @staticmethod
    def calculate_price(
        db: Session,
        request: PriceCalculationRequest,
        employee: StaffEmployee
    ) -> PriceCalculationPreview:
        """Calculate price with markup and incentive preview"""
        validate_accounts_access(employee)
        
        markup_pct = request.markup_pct
        incentive_pct = request.incentive_pct
        
        if request.company_id:
            config = db.query(PricingConfiguration).filter(
                PricingConfiguration.company_id == request.company_id,
                PricingConfiguration.is_active == True
            ).first()
            
            if config:
                if markup_pct is None:
                    markup_pct = config.default_markup_pct
                if incentive_pct is None:
                    incentive_pct = config.incentive_pct
        
        if markup_pct is None:
            markup_pct = Decimal("20.00")
        if incentive_pct is None:
            incentive_pct = Decimal("50.00")
        
        purchase_cost = request.purchase_cost
        default_price = purchase_cost + (purchase_cost * markup_pct / Decimal("100"))
        
        if request.custom_price is not None:
            final_price = request.custom_price
            is_below_cost = final_price < purchase_cost
        else:
            final_price = default_price
            is_below_cost = False
        
        profit_per_unit = final_price - purchase_cost
        if profit_per_unit < 0:
            profit_per_unit = Decimal("0")
        
        incentive_amount = profit_per_unit * (incentive_pct / Decimal("100")) * request.quantity
        
        return PriceCalculationPreview(
            purchase_cost=purchase_cost,
            markup_pct=markup_pct,
            default_price=default_price,
            custom_price=request.custom_price,
            final_price=final_price,
            profit_per_unit=profit_per_unit,
            incentive_pct=incentive_pct,
            incentive_amount=incentive_amount,
            is_below_cost=is_below_cost
        )


# ==================== HSN MASTER SERVICE ====================

class HSNMasterService:
    """
    Service for HSN/SAC Code Master operations.
    DC_HSN_001: CRUD with GST rate management and calculation.
    DC_RBAC: VGK4U Supreme, EA, and Accounts team have equal full access.
    """
    
    @staticmethod
    def create_hsn(
        db: Session,
        data: 'HSNMasterCreate',
        employee: StaffEmployee
    ) -> HSNMaster:
        """Create a new HSN code entry"""
        validate_accounts_access(employee)
        
        existing = db.query(HSNMaster).filter(
            func.upper(HSNMaster.hsn_code) == data.hsn_code.upper().strip()
        ).first()
        
        if existing:
            raise AccountsDuplicateError(
                f"HSN code '{data.hsn_code}' already exists"
            )
        
        hsn = HSNMaster(
            hsn_code=data.hsn_code.upper().strip(),
            description=data.description.strip(),
            cgst_rate=data.cgst_rate,
            sgst_rate=data.sgst_rate,
            igst_rate=data.igst_rate,
            cess_rate=data.cess_rate or Decimal("0.00"),
            effective_from=data.effective_from,
            effective_to=data.effective_to,
            is_active=data.is_active,
            created_by_id=employee.id
        )
        
        db.add(hsn)
        db.commit()
        db.refresh(hsn)
        
        log_accounts_audit(
            db=db,
            employee_id=employee.id,
            action="CREATE",
            entity_type="HSN_MASTER",
            entity_id=hsn.id,
            description=f"Created HSN code: {hsn.hsn_code}"
        )
        
        return hsn
    
    @staticmethod
    def update_hsn(
        db: Session,
        hsn_id: int,
        data: 'HSNMasterUpdate',
        employee: StaffEmployee
    ) -> HSNMaster:
        """Update an existing HSN code"""
        validate_accounts_access(employee)
        
        hsn = db.query(HSNMaster).filter(HSNMaster.id == hsn_id).first()
        if not hsn:
            raise AccountsNotFoundError(f"HSN code with ID {hsn_id} not found")
        
        if data.hsn_code:
            existing = db.query(HSNMaster).filter(
                func.upper(HSNMaster.hsn_code) == data.hsn_code.upper().strip(),
                HSNMaster.id != hsn_id
            ).first()
            if existing:
                raise AccountsDuplicateError(
                    f"HSN code '{data.hsn_code}' already exists"
                )
            hsn.hsn_code = data.hsn_code.upper().strip()
        
        if data.description is not None:
            hsn.description = data.description.strip()
        if data.cgst_rate is not None:
            hsn.cgst_rate = data.cgst_rate
        if data.sgst_rate is not None:
            hsn.sgst_rate = data.sgst_rate
        if data.igst_rate is not None:
            hsn.igst_rate = data.igst_rate
        if data.cess_rate is not None:
            hsn.cess_rate = data.cess_rate
        if data.effective_from is not None:
            hsn.effective_from = data.effective_from
        if data.effective_to is not None:
            hsn.effective_to = data.effective_to
        if data.is_active is not None:
            hsn.is_active = data.is_active
        
        hsn.updated_by_id = employee.id
        
        db.commit()
        db.refresh(hsn)
        
        log_accounts_audit(
            db=db,
            employee_id=employee.id,
            action="UPDATE",
            entity_type="HSN_MASTER",
            entity_id=hsn.id,
            description=f"Updated HSN code: {hsn.hsn_code}"
        )
        
        return hsn
    
    @staticmethod
    def get_hsn_by_id(db: Session, hsn_id: int) -> Optional[HSNMaster]:
        """Get HSN code by ID"""
        return db.query(HSNMaster).filter(HSNMaster.id == hsn_id).first()
    
    @staticmethod
    def get_hsn_by_code(db: Session, hsn_code: str) -> Optional[HSNMaster]:
        """Get HSN code by code string"""
        return db.query(HSNMaster).filter(
            func.upper(HSNMaster.hsn_code) == hsn_code.upper().strip()
        ).first()
    
    @staticmethod
    def list_hsn_codes(
        db: Session,
        skip: int = 0,
        limit: int = 100,
        search: Optional[str] = None,
        is_active: Optional[bool] = None
    ) -> Tuple[List[HSNMaster], int]:
        """List HSN codes with pagination and filtering"""
        query = db.query(HSNMaster)
        
        if is_active is not None:
            query = query.filter(HSNMaster.is_active == is_active)
        
        if search:
            search_term = f"%{search}%"
            query = query.filter(
                or_(
                    HSNMaster.hsn_code.ilike(search_term),
                    HSNMaster.description.ilike(search_term)
                )
            )
        
        total = query.count()
        hsn_codes = query.order_by(HSNMaster.hsn_code).offset(skip).limit(limit).all()
        
        return hsn_codes, total
    
    @staticmethod
    def delete_hsn(
        db: Session,
        hsn_id: int,
        employee: StaffEmployee
    ) -> bool:
        """Soft delete HSN code (set is_active=False)"""
        validate_accounts_access(employee)
        
        hsn = db.query(HSNMaster).filter(HSNMaster.id == hsn_id).first()
        if not hsn:
            raise AccountsNotFoundError(f"HSN code with ID {hsn_id} not found")
        
        hsn.is_active = False
        hsn.updated_by_id = employee.id
        
        db.commit()
        
        log_accounts_audit(
            db=db,
            employee_id=employee.id,
            action="DELETE",
            entity_type="HSN_MASTER",
            entity_id=hsn.id,
            description=f"Deactivated HSN code: {hsn.hsn_code}"
        )
        
        return True
    
    @staticmethod
    def calculate_gst(
        db: Session,
        request: 'GSTCalculationRequest'
    ) -> 'GSTCalculationResponse':
        """
        Calculate GST based on HSN code and transaction type.
        DC_GST_CALC_001: Determines intra-state (CGST+SGST) vs inter-state (IGST)
        """
        hsn = db.query(HSNMaster).filter(
            func.upper(HSNMaster.hsn_code) == request.hsn_code.upper().strip(),
            HSNMaster.is_active == True
        ).first()
        
        if not hsn:
            raise AccountsNotFoundError(f"HSN code '{request.hsn_code}' not found or inactive")
        
        seller_state = request.seller_state.strip().lower()
        buyer_state = request.buyer_state.strip().lower()
        is_intra_state = seller_state == buyer_state
        
        rates = hsn.get_gst_rates(is_intra_state)
        taxable = request.taxable_amount
        
        cgst_amount = taxable * Decimal(str(rates['cgst_rate'])) / Decimal("100")
        sgst_amount = taxable * Decimal(str(rates['sgst_rate'])) / Decimal("100")
        igst_amount = taxable * Decimal(str(rates['igst_rate'])) / Decimal("100")
        cess_amount = taxable * Decimal(str(rates['cess_rate'])) / Decimal("100")
        
        total_gst = cgst_amount + sgst_amount + igst_amount + cess_amount
        total_amount = taxable + total_gst
        
        return GSTCalculationResponse(
            hsn_code=hsn.hsn_code,
            taxable_amount=taxable,
            is_intra_state=is_intra_state,
            cgst_rate=Decimal(str(rates['cgst_rate'])),
            sgst_rate=Decimal(str(rates['sgst_rate'])),
            igst_rate=Decimal(str(rates['igst_rate'])),
            cess_rate=Decimal(str(rates['cess_rate'])),
            cgst_amount=cgst_amount.quantize(Decimal("0.01")),
            sgst_amount=sgst_amount.quantize(Decimal("0.01")),
            igst_amount=igst_amount.quantize(Decimal("0.01")),
            cess_amount=cess_amount.quantize(Decimal("0.01")),
            total_gst=total_gst.quantize(Decimal("0.01")),
            total_amount=total_amount.quantize(Decimal("0.01"))
        )


