# ==================== VENDOR TRANSACTION SERVICE (Phase 2.9) ====================

class VendorTransactionService:
    """
    Service for Vendor Transaction operations.
    DC_SFMS_001: Purchase/Payment transactions with header + line items.
    Status workflow: DRAFT → SUBMITTED → APPROVED → PAID/CANCELLED
    VGK/EA/Accounts have equal full permissions.
    """
    
    # Valid status transitions
    STATUS_TRANSITIONS = {
        'DRAFT': ['SUBMITTED', 'CANCELLED'],
        'SUBMITTED': ['APPROVED', 'REJECTED', 'DRAFT'],
        'APPROVED': ['PAID', 'CANCELLED'],
        'PAID': [],
        'CANCELLED': ['DRAFT'],
        'REJECTED': ['DRAFT']
    }
    
    @staticmethod
    def _generate_transaction_number(db: Session, company_id: int, transaction_type: str) -> str:
        """Generate unique transaction number: VT-{TYPE_PREFIX}-{COMPANY}-{YYYYMM}-{SEQ}"""
        from app.models.staff_accounts import VendorTransactionHeader
        
        company = db.query(AssociatedCompany).filter(
            AssociatedCompany.id == company_id
        ).first()
        company_code = company.company_code[:3].upper() if company else "XXX"
        
        type_prefix = {
            'PURCHASE': 'PUR',
            'PAYMENT': 'PAY',
            'ADVANCE': 'ADV',
            'REFUND': 'REF',
            'DEBIT_NOTE': 'DN',
            'CREDIT_NOTE': 'CN'
        }.get(transaction_type, 'VT')
        
        now = get_indian_time()
        prefix = f"VT-{type_prefix}-{company_code}-{now.strftime('%Y%m')}"
        
        # DC-TXN-SEQ-001: Advisory lock scoped to this DB transaction prevents
        # concurrent confirms from generating duplicate transaction numbers.
        # COUNT-based approach had a race condition when two confirms ran within
        # the same DB transaction window — both saw the same committed-row count
        # and produced the same sequence number (collision confirmed: ids 46+47,
        # 28-May-2026). pg_advisory_xact_lock is auto-released on commit/rollback.
        from sqlalchemy import text as _seq_sql
        db.execute(_seq_sql(
            "SELECT pg_advisory_xact_lock(hashtext(:p)::bigint)"
        ), {"p": prefix})

        count = db.query(VendorTransactionHeader).filter(
            VendorTransactionHeader.transaction_number.like(f"{prefix}%")
        ).count()
        
        return f"{prefix}-{count + 1:04d}"
    
    @staticmethod
    def _calculate_line_item_amounts(item_data: dict, is_igst: bool = False) -> dict:
        """Calculate all amounts for a line item including GST"""
        quantity = Decimal(str(item_data.get('quantity', 1)))
        unit_rate = Decimal(str(item_data.get('unit_rate', 0)))
        discount_percent = Decimal(str(item_data.get('discount_percent', 0)))
        gst_rate = Decimal(str(item_data.get('gst_rate', 0)))
        
        gross_amount = quantity * unit_rate
        discount_amount = (gross_amount * discount_percent / Decimal('100')).quantize(Decimal('0.01'))
        taxable_amount = (gross_amount - discount_amount).quantize(Decimal('0.01'))
        
        total_gst = (taxable_amount * gst_rate / Decimal('100')).quantize(Decimal('0.01'))
        
        if is_igst:
            cgst_amount = Decimal('0')
            sgst_amount = Decimal('0')
            igst_amount = total_gst
        else:
            cgst_amount = (total_gst / Decimal('2')).quantize(Decimal('0.01'))
            sgst_amount = (total_gst / Decimal('2')).quantize(Decimal('0.01'))
            igst_amount = Decimal('0')
        
        total_amount = taxable_amount + total_gst
        
        ok_qty = item_data.get('ok_qty')
        if ok_qty is None:
            ok_qty = quantity - Decimal(str(item_data.get('defective_qty', 0)))
        
        return {
            'discount_amount': discount_amount,
            'taxable_amount': taxable_amount,
            'cgst_amount': cgst_amount,
            'sgst_amount': sgst_amount,
            'igst_amount': igst_amount,
            'total_amount': total_amount,
            'ok_qty': ok_qty
        }
    
    @staticmethod
    def _recalculate_header_totals(db: Session, transaction_id: int):
        """Recalculate header totals from line items"""
        from app.models.staff_accounts import VendorTransactionHeader, VendorTransactionLineItem
        
        header = db.query(VendorTransactionHeader).filter(
            VendorTransactionHeader.id == transaction_id
        ).first()
        
        if not header:
            return
        
        line_items = db.query(VendorTransactionLineItem).filter(
            VendorTransactionLineItem.transaction_id == transaction_id
        ).all()
        
        subtotal = Decimal('0')
        total_discount = Decimal('0')
        taxable_amount = Decimal('0')
        total_cgst = Decimal('0')
        total_sgst = Decimal('0')
        total_igst = Decimal('0')
        
        for item in line_items:
            subtotal += item.quantity * item.unit_rate
            total_discount += item.discount_amount
            taxable_amount += item.taxable_amount
            total_cgst += item.cgst_amount
            total_sgst += item.sgst_amount
            total_igst += item.igst_amount
        
        total_gst = total_cgst + total_sgst + total_igst
        grand_total = taxable_amount + total_gst + header.round_off - header.total_tds
        balance_due = grand_total - header.amount_paid
        
        header.subtotal = subtotal
        header.total_discount = total_discount
        header.taxable_amount = taxable_amount
        header.total_cgst = total_cgst
        header.total_sgst = total_sgst
        header.total_igst = total_igst
        header.total_gst = total_gst
        header.grand_total = grand_total
        header.balance_due = balance_due
        header.updated_at = get_indian_time()
    
    @staticmethod
    def _create_ledger_entries_on_approval(
        db: Session,
        transaction: 'VendorTransactionHeader',
        employee: StaffEmployee
    ) -> None:
        """
        Create stock and party ledger entries when transaction is approved.
        DC_SFMS_001: Automatic ledger entry creation on approval.
        Includes idempotency checks to prevent duplicate entries.
        """
        from app.models.staff_accounts import VendorMaster, StockLedger, PartyLedger
        
        existing_stock = db.query(StockLedger).filter(
            StockLedger.reference_type == 'VENDOR_TXN',
            StockLedger.reference_id == transaction.id
        ).first()
        
        existing_party = db.query(PartyLedger).filter(
            PartyLedger.reference_type == 'VENDOR_TXN',
            PartyLedger.reference_id == transaction.id
        ).first()
        
        if existing_stock or existing_party:
            return
        
        vendor = db.query(VendorMaster).filter(
            VendorMaster.id == transaction.vendor_id
        ).first()
        
        if not vendor:
            return
        
        transaction_date = transaction.transaction_date or date.today()
        
        if transaction.record_type == 'PRODUCT' and transaction.transaction_type == 'PURCHASE':
            for line_item in transaction.line_items:
                if line_item.item_id:
                    StockLedgerService.create_entry(
                        db=db,
                        company_id=transaction.company_id,
                        item_id=line_item.item_id,
                        transaction_date=transaction_date,
                        entry_type='PURCHASE',
                        reference_type='VENDOR_TXN',
                        reference_id=transaction.id,
                        reference_number=transaction.transaction_number,
                        quantity_in=line_item.quantity,
                        quantity_out=Decimal('0'),
                        unit_rate=line_item.unit_rate,
                        segment_id=transaction.segment_id,
                        remarks=f"Purchase from {vendor.vendor_name}"
                    )
        
        if transaction.transaction_type == 'PURCHASE':
            PartyLedgerService.create_entry(
                db=db,
                party_type='VENDOR',
                party_id=transaction.vendor_id,
                party_name=vendor.vendor_name,
                company_id=transaction.company_id,
                transaction_date=transaction_date,
                entry_type='CREDIT',
                reference_type='VENDOR_TXN',
                reference_id=transaction.id,
                reference_number=transaction.transaction_number,
                debit_amount=Decimal('0'),
                credit_amount=transaction.grand_total,
                narration=f"Purchase invoice: {transaction.invoice_number or transaction.transaction_number}",
                segment_id=transaction.segment_id
            )
        elif transaction.transaction_type == 'PAYMENT':
            PartyLedgerService.create_entry(
                db=db,
                party_type='VENDOR',
                party_id=transaction.vendor_id,
                party_name=vendor.vendor_name,
                company_id=transaction.company_id,
                transaction_date=transaction_date,
                entry_type='DEBIT',
                reference_type='VENDOR_TXN',
                reference_id=transaction.id,
                reference_number=transaction.transaction_number,
                debit_amount=transaction.grand_total,
                credit_amount=Decimal('0'),
                narration=f"Payment to vendor: {transaction.transaction_number}",
                segment_id=transaction.segment_id
            )
        
        log_accounts_audit(
            db=db,
            employee_id=employee.id,
            action="CREATE_LEDGER_ENTRIES",
            entity_type="VendorTransactionHeader",
            entity_id=transaction.id,
            old_values=None,
            new_values={"transaction_type": transaction.transaction_type, "record_type": transaction.record_type},
            description=f"Created ledger entries for approved transaction: {transaction.transaction_number}"
        )
    
    @staticmethod
    def create_transaction(
        db: Session,
        data: 'VendorTransactionCreate',
        employee: StaffEmployee
    ) -> 'VendorTransactionHeader':
        """Create a new vendor transaction with line items (atomic)"""
        from app.models.staff_accounts import VendorTransactionHeader, VendorTransactionLineItem
        from app.schemas.staff_accounts import VendorTransactionCreate
        
        validate_accounts_access(employee)
        
        company = db.query(AssociatedCompany).filter(
            AssociatedCompany.id == data.company_id,
            AssociatedCompany.is_active == True
        ).first()
        if not company:
            raise AccountsNotFoundError(f"Company with ID {data.company_id} not found or inactive")
        
        if data.segment_id:
            segment = db.query(CompanySegment).filter(
                CompanySegment.id == data.segment_id,
                CompanySegment.company_id == data.company_id,
                CompanySegment.is_active == True
            ).first()
            if not segment:
                raise AccountsNotFoundError(f"Segment with ID {data.segment_id} not found for this company")
        
        vendor = db.query(VendorMaster).filter(
            VendorMaster.id == data.vendor_id,
            VendorMaster.is_active == True
        ).first()
        if not vendor:
            raise AccountsNotFoundError(f"Vendor with ID {data.vendor_id} not found or inactive")
        
        transaction_number = VendorTransactionService._generate_transaction_number(
            db, data.company_id, data.transaction_type
        )
        
        transaction = VendorTransactionHeader(
            transaction_number=transaction_number,
            company_id=data.company_id,
            segment_id=data.segment_id,
            vendor_id=data.vendor_id,
            transaction_date=data.transaction_date,
            transaction_type=data.transaction_type,
            record_type=data.record_type,
            payment_mode=data.payment_mode,
            payment_reference=data.payment_reference,
            payment_date=data.payment_date,
            vendor_invoice_no=data.vendor_invoice_no,
            vendor_invoice_date=data.vendor_invoice_date,
            invoice_status=data.invoice_status,
            category_id=data.category_id,
            narration=data.narration,
            remarks=data.remarks,
            status='DRAFT',
            created_by_id=employee.id
        )
        
        db.add(transaction)
        db.flush()
        
        for line_num, item_data in enumerate(data.line_items, 1):
            item_dict = item_data.model_dump()
            is_igst = item_dict.pop('is_igst', False)
            amounts = VendorTransactionService._calculate_line_item_amounts(item_dict, is_igst)
            
            line_item = VendorTransactionLineItem(
                transaction_id=transaction.id,
                line_number=line_num,
                item_id=item_data.item_id,
                item_code=item_data.item_code,
                item_description=item_data.item_description,
                hsn_code=item_data.hsn_code,
                quantity=item_data.quantity,
                unit_of_measure=item_data.unit_of_measure,
                unit_rate=item_data.unit_rate,
                discount_percent=item_data.discount_percent,
                discount_amount=amounts['discount_amount'],
                taxable_amount=amounts['taxable_amount'],
                gst_rate=item_data.gst_rate,
                cgst_amount=amounts['cgst_amount'],
                sgst_amount=amounts['sgst_amount'],
                igst_amount=amounts['igst_amount'],
                total_amount=amounts['total_amount'],
                product_status=item_data.product_status,
                defective_qty=item_data.defective_qty,
                ok_qty=amounts['ok_qty'],
                service_status=item_data.service_status,
                service_date=item_data.service_date
            )
            db.add(line_item)
        
        db.flush()
        VendorTransactionService._recalculate_header_totals(db, transaction.id)
        
        db.commit()
        db.refresh(transaction)
        
        log_accounts_audit(
            db=db,
            employee_id=employee.id,
            action="CREATE_VENDOR_TXN",
            entity_type="VendorTransactionHeader",
            entity_id=transaction.id,
            new_values={
                "transaction_number": transaction.transaction_number,
                "vendor_id": transaction.vendor_id,
                "transaction_type": transaction.transaction_type,
                "grand_total": str(transaction.grand_total)
            },
            description=f"Created vendor transaction: {transaction.transaction_number}"
        )
        
        return transaction
    
    @staticmethod
    def get_transaction(db: Session, transaction_id: int, employee: StaffEmployee) -> 'VendorTransactionHeader':
        """Get a vendor transaction by ID with line items"""
        from app.models.staff_accounts import VendorTransactionHeader
        
        validate_accounts_access(employee)
        
        transaction = db.query(VendorTransactionHeader).filter(
            VendorTransactionHeader.id == transaction_id
        ).first()
        
        if not transaction:
            raise AccountsNotFoundError(f"Vendor transaction with ID {transaction_id} not found")
        
        return transaction
    
    @staticmethod
    def list_transactions(
        db: Session,
        employee: StaffEmployee,
        page: int = 1,
        page_size: int = 20,
        company_id: Optional[int] = None,
        vendor_id: Optional[int] = None,
        transaction_type: Optional[str] = None,
        status: Optional[str] = None,
        date_from: Optional[date] = None,
        date_to: Optional[date] = None,
        search: Optional[str] = None
    ) -> Tuple[List['VendorTransactionHeader'], int]:
        """List vendor transactions with filters"""
        from app.models.staff_accounts import VendorTransactionHeader
        
        validate_accounts_access(employee)
        
        query = db.query(VendorTransactionHeader)
        
        if company_id:
            query = query.filter(VendorTransactionHeader.company_id == company_id)
        
        if vendor_id:
            query = query.filter(VendorTransactionHeader.vendor_id == vendor_id)
        
        if transaction_type:
            query = query.filter(VendorTransactionHeader.transaction_type == transaction_type)
        
        if status:
            query = query.filter(VendorTransactionHeader.status == status)
        
        if date_from:
            query = query.filter(VendorTransactionHeader.transaction_date >= date_from)
        
        if date_to:
            query = query.filter(VendorTransactionHeader.transaction_date <= date_to)
        
        if search:
            search_pattern = f"%{search}%"
            query = query.filter(
                or_(
                    VendorTransactionHeader.transaction_number.ilike(search_pattern),
                    VendorTransactionHeader.vendor_invoice_no.ilike(search_pattern),
                    VendorTransactionHeader.narration.ilike(search_pattern)
                )
            )
        
        total = query.count()
        
        transactions = query.order_by(
            desc(VendorTransactionHeader.transaction_date),
            desc(VendorTransactionHeader.created_at)
        ).offset((page - 1) * page_size).limit(page_size).all()
        
        return transactions, total
    
    @staticmethod
    def update_transaction(
        db: Session,
        transaction_id: int,
        data: 'VendorTransactionUpdate',
        employee: StaffEmployee
    ) -> 'VendorTransactionHeader':
        """Update vendor transaction (DRAFT status only for most fields)"""
        from app.models.staff_accounts import VendorTransactionHeader
        
        validate_accounts_access(employee)
        
        transaction = db.query(VendorTransactionHeader).filter(
            VendorTransactionHeader.id == transaction_id
        ).first()
        
        if not transaction:
            raise AccountsNotFoundError(f"Vendor transaction with ID {transaction_id} not found")
        
        if transaction.status != 'DRAFT':
            allowed_fields = {'amount_paid', 'payment_mode', 'payment_reference', 'payment_date',
                             'invoice_status', 'invoice_received_on', 'invoice_path', 'remarks'}
            update_data = data.model_dump(exclude_unset=True)
            for field in update_data.keys():
                if field not in allowed_fields:
                    raise AccountsValidationError(
                        f"Cannot modify {field} after transaction is submitted. Status: {transaction.status}"
                    )
        
        old_values = {"status": transaction.status, "grand_total": str(transaction.grand_total)}
        
        update_data = data.model_dump(exclude_unset=True)
        
        for field, value in update_data.items():
            if hasattr(transaction, field):
                setattr(transaction, field, value)
        
        if 'amount_paid' in update_data:
            transaction.balance_due = transaction.grand_total - transaction.amount_paid
        
        transaction.updated_by_id = employee.id  # DC Protocol audit trail
        transaction.updated_at = get_indian_time()
        
        db.commit()
        db.refresh(transaction)
        
        log_accounts_audit(
            db=db,
            employee_id=employee.id,
            action="UPDATE_VENDOR_TXN",
            entity_type="VendorTransactionHeader",
            entity_id=transaction.id,
            old_values=old_values,
            new_values={"status": transaction.status, "grand_total": str(transaction.grand_total)},
            description=f"Updated vendor transaction: {transaction.transaction_number}"
        )
        
        return transaction
    
    @staticmethod
    def change_status(
        db: Session,
        transaction_id: int,
        new_status: str,
        employee: StaffEmployee,
        reason: Optional[str] = None
    ) -> 'VendorTransactionHeader':
        """Change transaction status with workflow validation"""
        from app.models.staff_accounts import VendorTransactionHeader
        
        validate_accounts_access(employee)
        
        transaction = db.query(VendorTransactionHeader).filter(
            VendorTransactionHeader.id == transaction_id
        ).first()
        
        if not transaction:
            raise AccountsNotFoundError(f"Vendor transaction with ID {transaction_id} not found")
        
        current_status = transaction.status
        allowed_transitions = VendorTransactionService.STATUS_TRANSITIONS.get(current_status, [])
        
        if new_status not in allowed_transitions:
            raise AccountsValidationError(
                f"Cannot change status from {current_status} to {new_status}. "
                f"Allowed transitions: {', '.join(allowed_transitions) if allowed_transitions else 'None'}"
            )
        
        if new_status == 'SUBMITTED':
            if not transaction.line_items or len(transaction.line_items) == 0:
                raise AccountsValidationError("Cannot submit transaction without line items")
        
        if new_status == 'APPROVED':
            transaction.approved_by_id = employee.id
            transaction.approved_at = get_indian_time()
            
            VendorTransactionService._create_ledger_entries_on_approval(db, transaction, employee)
        
        if new_status == 'PAID':
            if transaction.balance_due > 0:
                raise AccountsValidationError(
                    f"Cannot mark as PAID with outstanding balance of {transaction.balance_due}"
                )
        
        if new_status in ['CANCELLED', 'REJECTED'] and not reason:
            raise AccountsValidationError(f"Reason is required for {new_status} status")
        
        old_status = transaction.status
        transaction.status = new_status
        transaction.updated_by_id = employee.id  # DC Protocol audit trail
        transaction.updated_at = get_indian_time()
        
        if reason:
            if transaction.remarks:
                transaction.remarks = f"{transaction.remarks}\n[{new_status}] {reason}"
            else:
                transaction.remarks = f"[{new_status}] {reason}"
        
        db.commit()
        db.refresh(transaction)
        
        log_accounts_audit(
            db=db,
            employee_id=employee.id,
            action=f"STATUS_CHANGE_{new_status}",
            entity_type="VendorTransactionHeader",
            entity_id=transaction.id,
            old_values={"status": old_status},
            new_values={"status": new_status, "reason": reason},
            description=f"Changed status from {old_status} to {new_status}: {transaction.transaction_number}"
        )
        
        return transaction
    
    @staticmethod
    def add_line_item(
        db: Session,
        transaction_id: int,
        item_data: 'VendorTransactionLineItemCreate',
        employee: StaffEmployee
    ) -> 'VendorTransactionLineItem':
        """Add a line item to a transaction (DRAFT only)"""
        from app.models.staff_accounts import VendorTransactionHeader, VendorTransactionLineItem
        
        validate_accounts_access(employee)
        
        transaction = db.query(VendorTransactionHeader).filter(
            VendorTransactionHeader.id == transaction_id
        ).first()
        
        if not transaction:
            raise AccountsNotFoundError(f"Vendor transaction with ID {transaction_id} not found")
        
        if transaction.status != 'DRAFT':
            raise AccountsValidationError(
                f"Cannot add line items to transaction with status: {transaction.status}"
            )
        
        max_line = db.query(func.max(VendorTransactionLineItem.line_number)).filter(
            VendorTransactionLineItem.transaction_id == transaction_id
        ).scalar() or 0
        
        item_dict = item_data.model_dump()
        is_igst = item_dict.pop('is_igst', False)
        amounts = VendorTransactionService._calculate_line_item_amounts(item_dict, is_igst)
        
        line_item = VendorTransactionLineItem(
            transaction_id=transaction_id,
            line_number=max_line + 1,
            item_id=item_data.item_id,
            item_code=item_data.item_code,
            item_description=item_data.item_description,
            hsn_code=item_data.hsn_code,
            quantity=item_data.quantity,
            unit_of_measure=item_data.unit_of_measure,
            unit_rate=item_data.unit_rate,
            discount_percent=item_data.discount_percent,
            discount_amount=amounts['discount_amount'],
            taxable_amount=amounts['taxable_amount'],
            gst_rate=item_data.gst_rate,
            cgst_amount=amounts['cgst_amount'],
            sgst_amount=amounts['sgst_amount'],
            igst_amount=amounts['igst_amount'],
            total_amount=amounts['total_amount'],
            product_status=item_data.product_status,
            defective_qty=item_data.defective_qty,
            ok_qty=amounts['ok_qty'],
            service_status=item_data.service_status,
            service_date=item_data.service_date
        )
        
        db.add(line_item)
        db.flush()
        
        VendorTransactionService._recalculate_header_totals(db, transaction_id)
        
        db.commit()
        db.refresh(line_item)
        
        log_accounts_audit(
            db=db,
            employee_id=employee.id,
            action="ADD_TXN_LINE_ITEM",
            entity_type="VendorTransactionLineItem",
            entity_id=line_item.id,
            new_values={"item_description": line_item.item_description, "total_amount": str(line_item.total_amount)},
            description=f"Added line item to transaction {transaction.transaction_number}"
        )
        
        return line_item
    
    @staticmethod
    def remove_line_item(
        db: Session,
        transaction_id: int,
        line_item_id: int,
        employee: StaffEmployee
    ) -> bool:
        """Remove a line item from a transaction (DRAFT only)"""
        from app.models.staff_accounts import VendorTransactionHeader, VendorTransactionLineItem
        
        validate_accounts_access(employee)
        
        transaction = db.query(VendorTransactionHeader).filter(
            VendorTransactionHeader.id == transaction_id
        ).first()
        
        if not transaction:
            raise AccountsNotFoundError(f"Vendor transaction with ID {transaction_id} not found")
        
        if transaction.status != 'DRAFT':
            raise AccountsValidationError(
                f"Cannot remove line items from transaction with status: {transaction.status}"
            )
        
        line_item = db.query(VendorTransactionLineItem).filter(
            VendorTransactionLineItem.id == line_item_id,
            VendorTransactionLineItem.transaction_id == transaction_id
        ).first()
        
        if not line_item:
            raise AccountsNotFoundError(f"Line item with ID {line_item_id} not found")
        
        old_values = {"item_description": line_item.item_description, "total_amount": str(line_item.total_amount)}
        
        db.delete(line_item)
        db.flush()
        
        VendorTransactionService._recalculate_header_totals(db, transaction_id)
        
        db.commit()
        
        log_accounts_audit(
            db=db,
            employee_id=employee.id,
            action="REMOVE_TXN_LINE_ITEM",
            entity_type="VendorTransactionLineItem",
            entity_id=line_item_id,
            old_values=old_values,
            description=f"Removed line item from transaction {transaction.transaction_number}"
        )
        
        return True


# ==================== SERVICE ITEMS USED SERVICE (Phase 2.10) ====================

class ServiceItemsUsedService:
    """
    Service for Service Items Used operations.
    DC_SFMS_001: Service items used with incentive calculation.
    Business Logic:
    - default_price = purchase_cost + (purchase_cost * default_markup_pct / 100)
    - final_price = custom_price if is_custom_price else default_price
    - profit_per_unit = final_price - purchase_cost  
    - total_profit = profit_per_unit * quantity_used
    - incentive_amount = total_profit * (incentive_pct / 100)
    VGK/EA/Accounts have equal full permissions.
    """
    
    @staticmethod
    def _calculate_pricing(
        db: Session,
        item_id: int,
        quantity_used: Decimal,
        custom_price: Optional[Decimal] = None
    ) -> dict:
        """Calculate all pricing and incentive values for a service item"""
        from app.models.staff_accounts import StockItemMaster, PricingConfiguration
        
        item = db.query(StockItemMaster).filter(
            StockItemMaster.id == item_id,
            StockItemMaster.is_active == True
        ).first()
        
        if not item:
            raise AccountsNotFoundError(f"Stock item with ID {item_id} not found or inactive")
        
        pricing_config = db.query(PricingConfiguration).filter(
            PricingConfiguration.company_id == item.company_id,
            PricingConfiguration.is_active == True
        ).first()
        
        default_markup_pct = Decimal('20')
        incentive_pct = Decimal('50')
        
        if pricing_config:
            default_markup_pct = pricing_config.default_markup_pct
            incentive_pct = pricing_config.incentive_pct
        
        purchase_cost = item.purchase_rate or Decimal('0')
        default_price = purchase_cost + (purchase_cost * default_markup_pct / Decimal('100'))
        default_price = default_price.quantize(Decimal('0.01'))
        
        is_custom_price = custom_price is not None
        final_price = custom_price if is_custom_price else default_price
        
        price_below_cost = final_price < purchase_cost
        
        profit_per_unit = final_price - purchase_cost
        total_cost = (purchase_cost * quantity_used).quantize(Decimal('0.01'))
        total_selling = (final_price * quantity_used).quantize(Decimal('0.01'))
        total_profit = (profit_per_unit * quantity_used).quantize(Decimal('0.01'))
        
        if total_profit > 0:
            incentive_amount = (total_profit * incentive_pct / Decimal('100')).quantize(Decimal('0.01'))
        else:
            incentive_amount = Decimal('0')
        
        return {
            'item': item,
            'purchase_cost': purchase_cost,
            'total_cost': total_cost,
            'default_price': default_price,
            'final_price': final_price,
            'total_selling': total_selling,
            'profit_per_unit': profit_per_unit.quantize(Decimal('0.01')),
            'total_profit': total_profit,
            'incentive_pct': incentive_pct,
            'incentive_amount': incentive_amount,
            'price_below_cost': price_below_cost,
            'is_custom_price': is_custom_price
        }
    
    @staticmethod
    def add_service_item(
        db: Session,
        transaction_id: int,
        item_id: int,
        quantity_used: Decimal,
        unit_of_measure: str,
        custom_price: Optional[Decimal],
        employee: StaffEmployee
    ) -> 'ServiceItemsUsed':
        """Add a service item used to a SERVICE transaction"""
        from app.models.staff_accounts import (
            VendorTransactionHeader, ServiceItemsUsed, StockItemMaster
        )
        
        validate_accounts_access(employee)
        
        transaction = db.query(VendorTransactionHeader).filter(
            VendorTransactionHeader.id == transaction_id
        ).first()
        
        if not transaction:
            raise AccountsNotFoundError(f"Transaction with ID {transaction_id} not found")
        
        if transaction.record_type != 'SERVICE':
            raise AccountsValidationError("Service items can only be added to SERVICE type transactions")
        
        if transaction.status not in ['DRAFT', 'SUBMITTED']:
            raise AccountsValidationError(f"Cannot add items to transaction with status: {transaction.status}")
        
        pricing = ServiceItemsUsedService._calculate_pricing(db, item_id, quantity_used, custom_price)
        item = pricing['item']
        
        max_line = db.query(func.max(ServiceItemsUsed.line_number)).filter(
            ServiceItemsUsed.transaction_id == transaction_id
        ).scalar() or 0
        
        service_item = ServiceItemsUsed(
            transaction_id=transaction_id,
            line_number=max_line + 1,
            item_id=item_id,
            item_code=item.item_code,
            item_name=item.item_name,
            available_stock=Decimal('0'),
            quantity_used=quantity_used,
            unit_of_measure=unit_of_measure,
            purchase_cost=pricing['purchase_cost'],
            total_cost=pricing['total_cost'],
            default_price=pricing['default_price'],
            custom_price=custom_price,
            final_price=pricing['final_price'],
            total_selling=pricing['total_selling'],
            profit_per_unit=pricing['profit_per_unit'],
            total_profit=pricing['total_profit'],
            incentive_pct=pricing['incentive_pct'],
            incentive_amount=pricing['incentive_amount'],
            price_below_cost=pricing['price_below_cost'],
            is_custom_price=pricing['is_custom_price']
        )
        
        db.add(service_item)
        db.commit()
        db.refresh(service_item)
        
        log_accounts_audit(
            db=db,
            employee_id=employee.id,
            action="ADD_SERVICE_ITEM",
            entity_type="ServiceItemsUsed",
            entity_id=service_item.id,
            new_values={
                "item_code": service_item.item_code,
                "quantity_used": str(service_item.quantity_used),
                "incentive_amount": str(service_item.incentive_amount)
            },
            description=f"Added service item {service_item.item_code} to transaction {transaction.transaction_number}"
        )
        
        return service_item
    
    @staticmethod
    def list_service_items(
        db: Session,
        transaction_id: int,
        employee: StaffEmployee
    ) -> Tuple[List['ServiceItemsUsed'], dict]:
        """List all service items for a transaction with totals"""
        from app.models.staff_accounts import VendorTransactionHeader, ServiceItemsUsed
        
        validate_accounts_access(employee)
        
        transaction = db.query(VendorTransactionHeader).filter(
            VendorTransactionHeader.id == transaction_id
        ).first()
        
        if not transaction:
            raise AccountsNotFoundError(f"Transaction with ID {transaction_id} not found")
        
        items = db.query(ServiceItemsUsed).filter(
            ServiceItemsUsed.transaction_id == transaction_id
        ).order_by(ServiceItemsUsed.line_number).all()
        
        totals = {
            'total_selling': sum(item.total_selling for item in items),
            'total_cost': sum(item.total_cost for item in items),
            'total_profit': sum(item.total_profit for item in items),
            'total_incentive': sum(item.incentive_amount for item in items)
        }
        
        return items, totals
    
    @staticmethod
    def remove_service_item(
        db: Session,
        transaction_id: int,
        service_item_id: int,
        employee: StaffEmployee
    ) -> bool:
        """Remove a service item from a transaction"""
        from app.models.staff_accounts import VendorTransactionHeader, ServiceItemsUsed
        
        validate_accounts_access(employee)
        
        transaction = db.query(VendorTransactionHeader).filter(
            VendorTransactionHeader.id == transaction_id
        ).first()
        
        if not transaction:
            raise AccountsNotFoundError(f"Transaction with ID {transaction_id} not found")
        
        if transaction.status not in ['DRAFT', 'SUBMITTED']:
            raise AccountsValidationError(f"Cannot remove items from transaction with status: {transaction.status}")
        
        service_item = db.query(ServiceItemsUsed).filter(
            ServiceItemsUsed.id == service_item_id,
            ServiceItemsUsed.transaction_id == transaction_id
        ).first()
        
        if not service_item:
            raise AccountsNotFoundError(f"Service item with ID {service_item_id} not found")
        
        if service_item.stock_deducted:
            raise AccountsValidationError("Cannot remove item after stock has been deducted")
        
        old_values = {
            "item_code": service_item.item_code,
            "quantity_used": str(service_item.quantity_used),
            "incentive_amount": str(service_item.incentive_amount)
        }
        
        db.delete(service_item)
        db.commit()
        
        log_accounts_audit(
            db=db,
            employee_id=employee.id,
            action="REMOVE_SERVICE_ITEM",
            entity_type="ServiceItemsUsed",
            entity_id=service_item_id,
            old_values=old_values,
            description=f"Removed service item from transaction {transaction.transaction_number}"
        )
        
        return True


# ==================== STOCK LEDGER SERVICE (Phase 2.11) ====================

class StockLedgerService:
    """
    Service for Stock Ledger operations.
    DC_SFMS_001: Company-wise stock movement with running balance.
    VGK/EA/Accounts have equal full permissions.
    """
    
    @staticmethod
    def _get_current_balance(db: Session, company_id: int, item_id: int) -> Tuple[Decimal, Decimal]:
        """Get current stock balance for an item at a company"""
        from app.models.staff_accounts import StockLedger
        
        last_entry = db.query(StockLedger).filter(
            StockLedger.company_id == company_id,
            StockLedger.item_id == item_id
        ).order_by(desc(StockLedger.id)).first()
        
        if last_entry:
            return last_entry.balance_qty, last_entry.balance_value
        return Decimal('0'), Decimal('0')
    
    @staticmethod
    def create_entry(
        db: Session,
        company_id: int,
        item_id: int,
        transaction_date: date,
        entry_type: str,
        reference_type: str,
        reference_id: int,
        reference_number: Optional[str],
        quantity_in: Decimal,
        quantity_out: Decimal,
        unit_rate: Decimal,
        narration: Optional[str],
        segment_id: Optional[int] = None
    ) -> 'StockLedger':
        """Create a stock ledger entry with running balance calculation"""
        from app.models.staff_accounts import StockLedger
        
        balance_qty, balance_value = StockLedgerService._get_current_balance(db, company_id, item_id)
        
        net_qty = quantity_in - quantity_out
        total_value = (net_qty * unit_rate).quantize(Decimal('0.01'))
        
        new_balance_qty = balance_qty + net_qty
        new_balance_value = balance_value + total_value
        
        entry = StockLedger(
            company_id=company_id,
            segment_id=segment_id,
            item_id=item_id,
            transaction_date=transaction_date,
            entry_type=entry_type,
            reference_type=reference_type,
            reference_id=reference_id,
            reference_number=reference_number,
            quantity_in=quantity_in,
            quantity_out=quantity_out,
            unit_rate=unit_rate,
            total_value=abs(total_value),
            balance_qty=new_balance_qty,
            balance_value=new_balance_value,
            narration=narration
        )

        db.add(entry)
        db.flush()  # assign entry.id before rebalance check
        # DC_STOCK_REBALANCE_001: if this entry is inserted out-of-chronological-order
        # (transaction_date < latest existing date for this item), retroactively correct
        # all subsequent running balance_qty / balance_value values.
        _needs_rebal = db.query(StockLedger).filter(
            StockLedger.company_id == company_id,
            StockLedger.item_id == item_id,
            StockLedger.id != entry.id,
            StockLedger.transaction_date > transaction_date
        ).limit(1).first()
        if _needs_rebal:
            StockLedgerService.rebalance_from_date(db, company_id, item_id, transaction_date)
        return entry

    @staticmethod
    def rebalance_from_date(
        db: Session,
        company_id: int,
        item_id: int,
        from_date: date
    ) -> int:
        """
        DC_STOCK_REBALANCE_001: Retroactively correct balance_qty + balance_value for
        all stock_ledger rows with transaction_date >= from_date for this (company, item).

        Anchor = SUM of ALL movements BEFORE from_date — always mathematically correct
        regardless of prior insertion order.  Entries at/after from_date are re-walked
        in (transaction_date ASC, id ASC) order so date-order = balance order.

        Returns number of rows whose stored balance differed and were corrected.
        Caller must commit the session to persist corrections.
        """
        from app.models.staff_accounts import StockLedger

        anchor_row = db.execute(text(
            "SELECT COALESCE(SUM(quantity_in - quantity_out), 0), "
            "       COALESCE(SUM((quantity_in - quantity_out) * unit_rate), 0) "
            "FROM stock_ledger "
            "WHERE company_id = :cid AND item_id = :iid AND transaction_date < :dt"
        ), {'cid': company_id, 'iid': item_id, 'dt': from_date}).fetchone()

        running_qty = Decimal(str(anchor_row[0])).quantize(Decimal('0.001'))
        running_val = Decimal(str(anchor_row[1])).quantize(Decimal('0.01'))

        entries = db.query(StockLedger).filter(
            StockLedger.company_id == company_id,
            StockLedger.item_id == item_id,
            StockLedger.transaction_date >= from_date
        ).order_by(StockLedger.transaction_date.asc(), StockLedger.id.asc()).all()

        corrected = 0
        for e in entries:
            qty_in  = Decimal(str(e.quantity_in  or 0))
            qty_out = Decimal(str(e.quantity_out or 0))
            net_qty = qty_in - qty_out
            net_val = (net_qty * Decimal(str(e.unit_rate or 0))).quantize(Decimal('0.01'))

            new_bal_qty = (running_qty + net_qty).quantize(Decimal('0.001'))
            new_bal_val = (running_val + net_val).quantize(Decimal('0.01'))

            if e.balance_qty != new_bal_qty or e.balance_value != new_bal_val:
                e.balance_qty   = new_bal_qty
                e.balance_value = new_bal_val
                corrected += 1

            running_qty = new_bal_qty
            running_val = new_bal_val

        return corrected

    @staticmethod
    def list_entries(
        db: Session,
        employee: StaffEmployee,
        company_id: Optional[int] = None,
        item_id: Optional[int] = None,
        entry_type: Optional[str] = None,
        date_from: Optional[date] = None,
        date_to: Optional[date] = None,
        page: int = 1,
        page_size: int = 20
    ) -> Tuple[List['StockLedger'], int]:
        """List stock ledger entries with filters"""
        from app.models.staff_accounts import StockLedger
        
        validate_accounts_access(employee)
        
        query = db.query(StockLedger)
        
        if company_id:
            query = query.filter(StockLedger.company_id == company_id)
        
        if item_id:
            query = query.filter(StockLedger.item_id == item_id)
        
        if entry_type:
            query = query.filter(StockLedger.entry_type == entry_type)
        
        if date_from:
            query = query.filter(StockLedger.transaction_date >= date_from)
        
        if date_to:
            query = query.filter(StockLedger.transaction_date <= date_to)
        
        total = query.count()
        
        entries = query.order_by(
            desc(StockLedger.transaction_date),
            desc(StockLedger.id)
        ).offset((page - 1) * page_size).limit(page_size).all()
        
        return entries, total
    
    @staticmethod
    def get_stock_balances(
        db: Session,
        employee: StaffEmployee,
        company_id: Optional[int] = None
    ) -> List[dict]:
        """Get current stock balances per item"""
        from app.models.staff_accounts import StockLedger, StockItemMaster
        
        validate_accounts_access(employee)
        
        subquery = db.query(
            StockLedger.company_id,
            StockLedger.item_id,
            func.max(StockLedger.id).label('max_id')
        ).group_by(StockLedger.company_id, StockLedger.item_id)
        
        if company_id:
            subquery = subquery.filter(StockLedger.company_id == company_id)
        
        subquery = subquery.subquery()
        
        entries = db.query(StockLedger, StockItemMaster).join(
            subquery,
            and_(
                StockLedger.id == subquery.c.max_id
            )
        ).join(
            StockItemMaster,
            StockLedger.item_id == StockItemMaster.id
        ).all()
        
        balances = []
        for ledger, item in entries:
            balances.append({
                'item_id': item.id,
                'item_code': item.item_code,
                'item_name': item.item_name,
                'company_id': ledger.company_id,
                'balance_qty': ledger.balance_qty,
                'balance_value': ledger.balance_value,
                'last_transaction_date': ledger.transaction_date
            })
        
        return balances


# ==================== PARTY LEDGER SERVICE (Phase 2.12) ====================

class PartyLedgerService:
    """
    Service for Party Ledger operations.
    DC_SFMS_001: Vendor/Employee/MNR User/External party debit/credit ledger.
    VGK/EA/Accounts have equal full permissions.
    """
    
    @staticmethod
    def _get_running_balance(db: Session, party_type: str, party_id: int, company_id: int, party_name: str = None) -> Decimal:
        """Get current running balance for a party.
        DC-PARTY-BAL-001: When party_id=0 (EXTERNAL), also filter by party_name to prevent
        cross-contamination between different external parties sharing party_id=0."""
        from app.models.staff_accounts import PartyLedger

        q = db.query(PartyLedger).filter(
            PartyLedger.party_type == party_type,
            PartyLedger.party_id == party_id,
            PartyLedger.company_id == company_id
        )
        if party_id == 0 and party_name:
            _norm = party_name.strip().upper()
            q = q.filter(PartyLedger.party_name == _norm)
        last_entry = q.order_by(desc(PartyLedger.id)).first()

        if last_entry:
            return last_entry.running_balance
        return Decimal('0')
    
    @staticmethod
    def create_entry(
        db: Session,
        party_type: str,
        party_id: int,
        party_name: str,
        company_id: int,
        transaction_date: date,
        entry_type: str,
        reference_type: str,
        reference_id: int,
        reference_number: Optional[str],
        debit_amount: Decimal,
        credit_amount: Decimal,
        narration: Optional[str],
        segment_id: Optional[int] = None
    ) -> 'PartyLedger':
        """Create a party ledger entry with running balance calculation"""
        from app.models.staff_accounts import PartyLedger
        
        # DC-PARTY-BAL-001: Pass party_name for EXTERNAL (party_id=0) isolation
        _norm_name_for_bal = party_name.strip().upper() if party_name else party_name
        current_balance = PartyLedgerService._get_running_balance(
            db, party_type, party_id, company_id, party_name=_norm_name_for_bal
        )

        new_balance = current_balance + debit_amount - credit_amount

        # DC-PNAME-NORM-001: Normalize party_name to UPPER case on every write
        # so name-case mismatches never produce duplicate rows in party-wise summary
        party_name = party_name.strip().upper() if party_name else party_name

        # DC-SOURCE-STATUS-001: Auto-derive source_status from reference_type
        _rt = reference_type or ''
        _src_status = (
            'MANUAL'          if _rt == 'MANUAL'
            else 'TALLY_IMPORT'    if _rt == 'TALLY_IMPORT'
            else 'OPENING_BALANCE' if _rt in ('OPENING', 'OPENING_BALANCE')
            else 'CONFIRMED'
        )

        entry = PartyLedger(
            party_type=party_type,
            party_id=party_id,
            party_name=party_name,
            company_id=company_id,
            segment_id=segment_id,
            transaction_date=transaction_date,
            entry_type=entry_type,
            reference_type=reference_type,
            reference_id=reference_id,
            reference_number=reference_number,
            debit_amount=debit_amount,
            credit_amount=credit_amount,
            running_balance=new_balance,
            narration=narration,
            source_status=_src_status,
        )
        
        db.add(entry)
        return entry

    @staticmethod
    def create_reversal(db: Session, original_entry: 'PartyLedger') -> 'PartyLedger':
        """DC-SHOW-IN-LEDGER-001: post an offsetting entry that cancels an earlier party ledger entry."""
        return PartyLedgerService.create_entry(
            db=db,
            party_type=original_entry.party_type,
            party_id=original_entry.party_id,
            party_name=original_entry.party_name,
            company_id=original_entry.company_id,
            transaction_date=get_indian_time().date(),
            entry_type='DEBIT' if original_entry.entry_type == 'CREDIT' else 'CREDIT',
            reference_type=original_entry.reference_type,
            reference_id=original_entry.reference_id,
            reference_number=original_entry.reference_number,
            debit_amount=original_entry.credit_amount,
            credit_amount=original_entry.debit_amount,
            narration=f"REVERSAL (Show in Ledger unchecked): {original_entry.narration}",
            segment_id=original_entry.segment_id
        )
    
    @staticmethod
    def list_entries(
        db: Session,
        employee: StaffEmployee,
        party_type: Optional[str] = None,
        party_id: Optional[int] = None,
        company_id: Optional[int] = None,
        date_from: Optional[date] = None,
        date_to: Optional[date] = None,
        page: int = 1,
        page_size: int = 20,
        party_name: Optional[str] = None,
        particulars: Optional[str] = None,
        reference_number: Optional[str] = None,
        reference_type: Optional[str] = None,
        source_status: Optional[str] = None,
    ) -> Tuple[List['PartyLedger'], int, dict]:
        """List party ledger entries with filters and summary"""
        from app.models.staff_accounts import PartyLedger
        
        validate_accounts_access(employee)
        
        query = db.query(PartyLedger)
        
        if party_type:
            query = query.filter(PartyLedger.party_type == party_type)
        
        # DC-PL-OR-FILTER-001 (Jun 2026): When both party_id and party_name are provided,
        # use OR so entries posted with a slightly different name spelling (e.g. vendor
        # canonical name vs user-typed name in JVs) still show under the same party view.
        # Without OR, purchase entries posted with party_name=VendorMaster.vendor_name
        # were hidden when the JV receipts used a different spelling of the same vendor.
        if party_id and party_name:
            from sqlalchemy import or_ as _or_pl
            query = query.filter(
                _or_pl(
                    PartyLedger.party_id == party_id,
                    PartyLedger.party_name.ilike(f'%{party_name}%')
                )
            )
        elif party_id:
            query = query.filter(PartyLedger.party_id == party_id)
        elif party_name:
            # DC: party_name search — fuzzy ILIKE match for external/customer parties
            query = query.filter(PartyLedger.party_name.ilike(f'%{party_name}%'))

        if company_id:
            query = query.filter(PartyLedger.company_id == company_id)

        # DC: particulars = stock item name / SKU search
        if particulars:
            query = query.filter(PartyLedger.particulars.ilike(f'%{particulars}%'))

        # DC: reference_number search (e.g. PO number, invoice number)
        if reference_number:
            query = query.filter(PartyLedger.reference_number.ilike(f'%{reference_number}%'))

        # DC: reference_type filter (e.g. INCOME, SALES_INVOICE, PURCHASE_INVOICE)
        if reference_type:
            query = query.filter(PartyLedger.reference_type == reference_type.upper())

        # DC-SOURCE-STATUS-001: multi-value source_status filter (comma-separated)
        if source_status:
            _statuses = [s.strip().upper() for s in source_status.split(',') if s.strip()]
            if _statuses:
                query = query.filter(PartyLedger.source_status.in_(_statuses))

        if date_from:
            query = query.filter(PartyLedger.transaction_date >= date_from)
        
        if date_to:
            query = query.filter(PartyLedger.transaction_date <= date_to)
        
        # DC-PARTY-OB-DISPLAY-001: Separate OPENING_BALANCE entries from regular entries
        # so the OB header shows vendor's set OB, not confusingly in Total Debit/Credit.
        opening_balance = Decimal('0')

        if date_from:
            # DC-PARTY-OB-DATE-001: Tally-style opening balance for date-filtered view.
            # Step 1: balance of last transaction strictly before date_from
            # Step 2: add any OPENING_BALANCE entries dated exactly on date_from (boundary fix —
            #         OB entries represent pre-existing balance, not period activity)
            # DC-UNIFIED-PARTY-001: build pre-period base query for any identity mode
            # Mode A: specific party_type + party_id (classic single-type lookup)
            # Mode B: name-only (unified party — all types for same name, same company)
            _pre_base = None
            if party_type and party_id:
                _pre_base = db.query(PartyLedger).filter(
                    PartyLedger.party_type == party_type,
                    PartyLedger.party_id == party_id
                )
                if company_id:
                    _pre_base = _pre_base.filter(PartyLedger.company_id == company_id)
            elif party_name:
                _pre_base = db.query(PartyLedger).filter(
                    PartyLedger.party_name.ilike(f'%{party_name}%')
                )
                if company_id:
                    _pre_base = _pre_base.filter(PartyLedger.company_id == company_id)

            if _pre_base is not None:
                # Last entry strictly before date_from (any reference type)
                last_pre = _pre_base.filter(
                    PartyLedger.transaction_date < date_from
                ).order_by(desc(PartyLedger.id)).first()
                if last_pre:
                    opening_balance = last_pre.running_balance

                # Also fold in OPENING_BALANCE entries dated exactly on date_from
                # (they are pre-period foundational entries, not period activity)
                ob_on_start = _pre_base.filter(
                    PartyLedger.transaction_date == date_from,
                    PartyLedger.reference_type == 'OPENING_BALANCE'
                ).all()
                for _ob_s in ob_on_start:
                    opening_balance += (_ob_s.credit_amount or Decimal('0')) - (_ob_s.debit_amount or Decimal('0'))

            # Exclude OPENING_BALANCE entries from the period entries list
            # (they're shown in the header as Opening Balance, not as ledger rows)
            entries_query = query.filter(PartyLedger.reference_type != 'OPENING_BALANCE')
        else:
            # Full-history view: exclude OPENING_BALANCE entries from entries list &
            # totals; compute OB separately so header shows the vendor's actual OB.
            entries_query = query.filter(PartyLedger.reference_type != 'OPENING_BALANCE')
            # DC-UNIFIED-PARTY-001: OB query works in both specific-ID and name-only mode
            if party_type and party_id:
                ob_base = db.query(PartyLedger).filter(
                    PartyLedger.party_type == party_type,
                    PartyLedger.party_id == party_id,
                    PartyLedger.reference_type == 'OPENING_BALANCE'
                )
                if company_id:
                    ob_base = ob_base.filter(PartyLedger.company_id == company_id)
                ob_sums = ob_base.with_entities(
                    func.coalesce(func.sum(PartyLedger.credit_amount), 0).label('ob_cr'),
                    func.coalesce(func.sum(PartyLedger.debit_amount), 0).label('ob_dr')
                ).first()
                if ob_sums and (ob_sums.ob_cr or ob_sums.ob_dr):
                    opening_balance = Decimal(str(ob_sums.ob_cr)) - Decimal(str(ob_sums.ob_dr))
                else:
                    # Fallback: AccountLedgerMaster PARTY row (legacy vendors created before DC-PARTY-OB-LEDGER-001)
                    try:
                        from app.models.staff_accounts import AccountLedgerMaster as _ALM_FB
                        from app.models.staff_accounts import VendorMaster as _VM_FB
                        from app.models.staff_accounts import OfficialPartner as _OP_FB
                        _party_name = None
                        if party_type == 'VENDOR':
                            _vm_fb = db.query(_VM_FB.vendor_name).filter(_VM_FB.id == party_id).first()
                            if _vm_fb:
                                _party_name = _vm_fb.vendor_name
                        elif party_type == 'PARTNER':
                            _op_fb = db.query(_OP_FB.partner_name).filter(_OP_FB.id == party_id).first()
                            if _op_fb:
                                _party_name = _op_fb.partner_name
                        if _party_name:
                            _alm_q = db.query(_ALM_FB).filter(
                                _ALM_FB.account_type == 'PARTY',
                                func.lower(_ALM_FB.account_name) == _party_name.strip().lower()
                            )
                            if company_id:
                                _alm_q = _alm_q.filter(_ALM_FB.company_id == company_id)
                            _alm_rows = _alm_q.all()
                            for _alm_r in _alm_rows:
                                if _alm_r.opening_balance:
                                    _sign = Decimal('1') if (_alm_r.opening_balance_type or 'CREDIT') == 'CREDIT' else Decimal('-1')
                                    opening_balance += Decimal(str(_alm_r.opening_balance)) * _sign
                    except Exception:
                        pass
            elif party_name:
                # Unified (name-only) mode: sum all OPENING_BALANCE rows for this name
                ob_base_n = db.query(PartyLedger).filter(
                    PartyLedger.party_name.ilike(f'%{party_name}%'),
                    PartyLedger.reference_type == 'OPENING_BALANCE'
                )
                if company_id:
                    ob_base_n = ob_base_n.filter(PartyLedger.company_id == company_id)
                ob_sums_n = ob_base_n.with_entities(
                    func.coalesce(func.sum(PartyLedger.credit_amount), 0).label('ob_cr'),
                    func.coalesce(func.sum(PartyLedger.debit_amount), 0).label('ob_dr')
                ).first()
                if ob_sums_n and (ob_sums_n.ob_cr or ob_sums_n.ob_dr):
                    opening_balance = Decimal(str(ob_sums_n.ob_cr)) - Decimal(str(ob_sums_n.ob_dr))

        total = entries_query.count()

        summary_query = entries_query.with_entities(
            func.sum(PartyLedger.debit_amount).label('total_debit'),
            func.sum(PartyLedger.credit_amount).label('total_credit')
        ).first()

        total_debit = summary_query.total_debit or Decimal('0')
        total_credit = summary_query.total_credit or Decimal('0')

        entries = entries_query.order_by(
            desc(PartyLedger.transaction_date),
            desc(PartyLedger.id)
        ).offset((page - 1) * page_size).limit(page_size).all()

        # DC-OB-DATE-SURFACE-001: fetch the actual OB date from party_ledger OPENING_BALANCE entry
        # so the frontend can display "As of 01 Apr 2026" instead of "As of start"
        ob_date_val = None
        try:
            _ob_date_q = db.query(PartyLedger.transaction_date).filter(
                PartyLedger.reference_type == 'OPENING_BALANCE'
            )
            if party_type and party_id:
                _ob_date_q = _ob_date_q.filter(
                    PartyLedger.party_type == party_type,
                    PartyLedger.party_id == party_id
                )
            elif party_name:
                _ob_date_q = _ob_date_q.filter(
                    PartyLedger.party_name.ilike(f'%{party_name}%')
                )
            if company_id:
                _ob_date_q = _ob_date_q.filter(PartyLedger.company_id == company_id)
            _ob_date_row = _ob_date_q.order_by(PartyLedger.transaction_date).first()
            if _ob_date_row:
                ob_date_val = str(_ob_date_row.transaction_date)
        except Exception:
            pass

        # For sign convention: positive OB means vendor is a creditor (CR balance = we owe them)
        # Closing = OB + Total Debit - Total Credit
        summary = {
            'opening_balance': opening_balance,
            'opening_balance_date': ob_date_val,
            'total_debit': total_debit,
            'total_credit': total_credit,
            'closing_balance': opening_balance + total_debit - total_credit
        }

        return entries, total, summary
    
    @staticmethod
    def get_party_balances(
        db: Session,
        employee: StaffEmployee,
        party_type: Optional[str] = None,
        company_id: Optional[int] = None
    ) -> List[dict]:
        """Get current balance summary per party"""
        from app.models.staff_accounts import PartyLedger
        
        validate_accounts_access(employee)
        
        subquery = db.query(
            PartyLedger.party_type,
            PartyLedger.party_id,
            PartyLedger.party_name,
            PartyLedger.company_id,
            func.max(PartyLedger.id).label('max_id'),
            func.sum(PartyLedger.debit_amount).label('total_debit'),
            func.sum(PartyLedger.credit_amount).label('total_credit'),
            func.max(PartyLedger.transaction_date).label('last_date')
        ).group_by(
            PartyLedger.party_type,
            PartyLedger.party_id,
            PartyLedger.party_name,
            PartyLedger.company_id
        )
        
        if party_type:
            subquery = subquery.filter(PartyLedger.party_type == party_type)
        
        if company_id:
            subquery = subquery.filter(PartyLedger.company_id == company_id)
        
        results = subquery.all()
        
        balances = []
        for row in results:
            last_entry = db.query(PartyLedger).filter(
                PartyLedger.id == row.max_id
            ).first()
            
            balances.append({
                'party_type': row.party_type,
                'party_id': row.party_id,
                'party_name': row.party_name,
                'company_id': row.company_id,
                'total_debit': row.total_debit or Decimal('0'),
                'total_credit': row.total_credit or Decimal('0'),
                'balance': last_entry.running_balance if last_entry else Decimal('0'),
                'last_transaction_date': row.last_date
            })
        
        return balances

    @staticmethod
    def get_party_summary(
        db: Session,
        employee: StaffEmployee,
        company_id: Optional[int] = None,
        party_type: Optional[str] = None,
        date_from=None,
        date_to=None,
    ) -> list:
        """
        DC-PWISE-001: Consolidated party-wise summary grouped by party_name + party_type.
        Supports date range and company filtering. Uses validate_accounts_access guard.
        Returns list of dicts: party_name, party_type, entry_count, total_debit,
        total_credit, net_balance, last_date.
        """
        from app.models.staff_accounts import PartyLedger
        validate_accounts_access(employee)

        # DC-PWISE-NORM-001: group by UPPER(party_name) so case-variant entries
        # (e.g. "Suresh enterprises" vs "SURESH ENTERPRISES") consolidate into one row.
        upper_name = func.upper(PartyLedger.party_name).label('party_name_upper')

        q = db.query(
            upper_name,
            PartyLedger.party_type,
            PartyLedger.company_id,
            func.count(PartyLedger.id).label('entry_count'),
            func.coalesce(func.sum(PartyLedger.debit_amount), 0).label('total_debit'),
            func.coalesce(func.sum(PartyLedger.credit_amount), 0).label('total_credit'),
            func.max(PartyLedger.transaction_date).label('last_date'),
        )
        if company_id:
            q = q.filter(PartyLedger.company_id == company_id)
        if party_type:
            q = q.filter(PartyLedger.party_type == party_type)
        if date_from:
            q = q.filter(PartyLedger.transaction_date >= date_from)
        if date_to:
            q = q.filter(PartyLedger.transaction_date <= date_to)

        rows = q.group_by(
            func.upper(PartyLedger.party_name),
            PartyLedger.party_type,
            PartyLedger.company_id,
        ).order_by(func.upper(PartyLedger.party_name)).all()

        result = []
        for r in rows:
            td = float(r.total_debit or 0)
            tc = float(r.total_credit or 0)
            result.append({
                'party_name': r.party_name_upper,
                'party_type': r.party_type,
                'company_id': r.company_id,
                'entry_count': int(r.entry_count),
                'total_debit': td,
                'total_credit': tc,
                'net_balance': td - tc,
                'last_date': r.last_date.isoformat() if r.last_date else None,
            })
        return result


# ==================== VENDOR RETURN SERVICE (Phase 2.13) ====================

class VendorReturnService:
    """
    Service for Vendor Return operations.
    DC_SFMS_001: Return/Refund tracking with credit note, replacement, refund options.
    Integrates with Stock Ledger and Party Ledger for reversal entries.
    VGK/EA/Accounts have equal full permissions.
    """
    
    STATUS_TRANSITIONS = {
        'INITIATED': ['IN_PROGRESS', 'CANCELLED'],
        'IN_PROGRESS': ['AWAITING_RESOLUTION', 'CANCELLED'],
        'AWAITING_RESOLUTION': ['RESOLVED', 'CANCELLED'],
        'RESOLVED': [],
        'CANCELLED': []
    }
    
    @staticmethod
    def _generate_return_number(db: Session, company_id: int) -> str:
        """Generate unique return number: RET-{company_code}-{YYYYMM}-{seq}"""
        from app.models.staff_accounts import VendorReturn
        
        company = db.query(AssociatedCompany).filter(
            AssociatedCompany.id == company_id
        ).first()
        company_code = company.company_code if company else 'UNK'
        
        now = get_indian_time()
        month_prefix = now.strftime('%Y%m')
        prefix = f"RET-{company_code}-{month_prefix}"
        
        last_return = db.query(VendorReturn).filter(
            VendorReturn.return_number.like(f"{prefix}%")
        ).order_by(desc(VendorReturn.id)).first()
        
        if last_return:
            try:
                last_seq = int(last_return.return_number.split('-')[-1])
                new_seq = last_seq + 1
            except (ValueError, IndexError):
                new_seq = 1
        else:
            new_seq = 1
        
        return f"{prefix}-{new_seq:04d}"
    
    @staticmethod
    def create_return(
        db: Session,
        data: 'VendorReturnCreate',
        employee: StaffEmployee
    ) -> 'VendorReturn':
        """Create a new vendor return"""
        from app.models.staff_accounts import VendorReturn, VendorTransactionHeader, VendorTransactionLineItem
        from app.schemas.staff_accounts import VendorReturnCreate
        
        validate_accounts_access(employee)
        
        transaction = db.query(VendorTransactionHeader).filter(
            VendorTransactionHeader.id == data.transaction_id
        ).first()
        
        if not transaction:
            raise AccountsNotFoundError(f"Transaction with ID {data.transaction_id} not found")
        
        if transaction.status not in ['APPROVED', 'PAID']:
            raise AccountsValidationError(
                f"Cannot create return for transaction with status: {transaction.status}. "
                "Only APPROVED or PAID transactions can have returns."
            )
        
        if data.line_item_id:
            line_item = db.query(VendorTransactionLineItem).filter(
                VendorTransactionLineItem.id == data.line_item_id,
                VendorTransactionLineItem.transaction_id == data.transaction_id
            ).first()
            
            if not line_item:
                raise AccountsNotFoundError(f"Line item with ID {data.line_item_id} not found in transaction")
            
            if data.return_qty > line_item.quantity:
                raise AccountsValidationError(
                    f"Return quantity ({data.return_qty}) exceeds original quantity ({line_item.quantity})"
                )
        
        return_number = VendorReturnService._generate_return_number(db, transaction.company_id)
        
        vendor_return = VendorReturn(
            return_number=return_number,
            transaction_id=data.transaction_id,
            line_item_id=data.line_item_id,
            company_id=transaction.company_id,
            vendor_id=transaction.vendor_id,
            return_date=data.return_date,
            return_qty=data.return_qty,
            return_value=data.return_value,
            return_reason=data.return_reason,
            return_remarks=data.return_remarks,
            resolution_status='PENDING',
            status='INITIATED',
            created_by_id=employee.id
        )
        
        db.add(vendor_return)
        db.commit()
        db.refresh(vendor_return)
        
        log_accounts_audit(
            db=db,
            employee_id=employee.id,
            action="CREATE_VENDOR_RETURN",
            entity_type="VendorReturn",
            entity_id=vendor_return.id,
            new_values={
                "return_number": vendor_return.return_number,
                "return_qty": str(vendor_return.return_qty),
                "return_value": str(vendor_return.return_value),
                "return_reason": vendor_return.return_reason
            },
            description=f"Created vendor return: {vendor_return.return_number}"
        )
        
        return vendor_return
    
    @staticmethod
    def get_return(
        db: Session,
        return_id: int,
        employee: StaffEmployee
    ) -> 'VendorReturn':
        """Get a vendor return by ID"""
        from app.models.staff_accounts import VendorReturn
        
