    @staticmethod
    def submit_spare_order(db: Session, employee: StaffEmployee, order_id: int):
        from app.models.staff_accounts import SparePurchaseOrder
        validate_accounts_access(employee)
        order = db.query(SparePurchaseOrder).filter(SparePurchaseOrder.id == order_id).first()
        if not order:
            raise AccountsNotFoundError(f"Spare order {order_id} not found")
        if order.status != 'DRAFT':
            raise AccountsValidationError("Only DRAFT orders can be submitted")
        if not order.lines:
            raise AccountsValidationError("Order has no items — add items before submitting")
        order.status = 'WAITING_APPROVAL'
        order.submitted_by_id = employee.id
        order.submitted_at = get_indian_time()
        order.updated_at = get_indian_time()
        db.commit()
        db.refresh(order)
        return order

    @staticmethod
    def approve_spare_order(
        db: Session, employee: StaffEmployee,
        order_id: int, approval_notes: str = None
    ):
        """
        Approve order (EA/Accounts/VGK only).
        Creates one ProcurementRequest per unique vendor — visible in Tab 1.
        """
        from app.models.staff_accounts import SparePurchaseOrder, ProcurementRequest, ProcurementRequestItem
        if not is_accounts_allowed_employee(employee):
            raise AccountsRBACError("Only Accounts, EA, or VGK roles can approve spare orders")
        order = db.query(SparePurchaseOrder).filter(SparePurchaseOrder.id == order_id).first()
        if not order:
            raise AccountsNotFoundError(f"Spare order {order_id} not found")
        if order.status != 'WAITING_APPROVAL':
            raise AccountsValidationError("Only orders in WAITING_APPROVAL can be approved")

        # Enforce: all lines must have vendor_id assigned before approval
        unassigned = [l for l in order.lines if not l.vendor_id]
        if unassigned:
            names = ', '.join(l.item_name or l.item_code or f'Item#{l.item_id}' for l in unassigned)
            raise AccountsValidationError(
                f"Cannot approve — {len(unassigned)} item(s) have no vendor assigned: {names}. "
                "Please assign a vendor to each item before approving."
            )

        # Group lines by vendor
        by_vendor: Dict[int, list] = {}
        for line in order.lines:
            by_vendor.setdefault(line.vendor_id, []).append(line)

        now = get_indian_time()
        req_ids = []

        for vendor_id, vendor_lines in by_vendor.items():
            # Generate procurement_request number
            prefix = f"PR-{now.strftime('%Y%m')}"
            cnt = db.query(ProcurementRequest).filter(
                ProcurementRequest.request_number.like(f"{prefix}%")
            ).count()
            req_number = f"{prefix}-{cnt + 1:04d}"

            pr = ProcurementRequest(
                request_number=req_number,
                company_id=order.company_id,
                request_date=now.date(),
                status='PO_CREATED',
                min_quotes_required=1,
                quotes_received_count=1,
                approved_vendor_id=vendor_id,
                notes=f"Auto-created from Spare PO {order.order_number}. {approval_notes or ''}".strip(),
                approved_at=now,
                approved_by_id=employee.id,
                approval_remarks=approval_notes,
                po_generated_at=now,
                created_by_id=employee.id,
            )
            db.add(pr)
            db.flush()

            for line in vendor_lines:
                pri = ProcurementRequestItem(
                    request_id=pr.id,
                    item_id=line.item_id,
                    required_qty=line.quantity,
                    unit_of_measure=line.unit_of_measure,
                    source_type='MANUAL',
                )
                db.add(pri)

            req_ids.append(pr.id)

        order.status = 'APPROVED'
        order.approved_by_id = employee.id
        order.approved_at = now
        order.approval_notes = approval_notes
        order.procurement_req_ids = req_ids
        order.updated_at = now
        db.commit()
        db.refresh(order)
        return order

    @staticmethod
    def review_update_spare_order(
        db: Session, employee: 'StaffEmployee', order_id: int,
        lines: list = None, deleted_line_ids: list = None,
    ):
        """
        DC-CONSOL-SPARE-001: Allow approver to update vendor/qty/rate and delete lines
        on a WAITING_APPROVAL order before final approval. Status stays WAITING_APPROVAL.
        """
        from app.models.staff_accounts import SparePurchaseOrder, SparePurchaseOrderLine
        if not is_accounts_allowed_employee(employee):
            raise AccountsRBACError("Only Accounts, EA, or VGK roles can review-update spare orders")
        order = db.query(SparePurchaseOrder).filter(SparePurchaseOrder.id == order_id).first()
        if not order:
            raise AccountsNotFoundError(f"Spare order {order_id} not found")
        if order.status != 'WAITING_APPROVAL':
            raise AccountsValidationError("Only WAITING_APPROVAL orders can be review-updated")

        # Delete specified lines
        for lid in (deleted_line_ids or []):
            db.query(SparePurchaseOrderLine).filter(
                SparePurchaseOrderLine.id == int(lid),
                SparePurchaseOrderLine.order_id == order.id,
            ).delete()

        # Update specified lines (vendor, qty, rate)
        for ld in (lines or []):
            line = db.query(SparePurchaseOrderLine).filter(
                SparePurchaseOrderLine.id == int(ld['id']),
                SparePurchaseOrderLine.order_id == order.id,
            ).first()
            if not line:
                continue
            raw_vid = ld.get('vendor_id')
            line.vendor_id = int(raw_vid) if raw_vid else None
            if ld.get('quantity') is not None:
                line.quantity = Decimal(str(ld['quantity']))
            if 'last_rate' in ld:
                line.last_purchase_rate = Decimal(str(ld['last_rate'])) if ld['last_rate'] else None

        order.updated_at = get_indian_time()
        db.commit()
        db.refresh(order)
        return order

    @staticmethod
    def cancel_spare_order(db: Session, employee: StaffEmployee, order_id: int):
        from app.models.staff_accounts import SparePurchaseOrder
        validate_accounts_access(employee)
        order = db.query(SparePurchaseOrder).filter(SparePurchaseOrder.id == order_id).first()
        if not order:
            raise AccountsNotFoundError(f"Spare order {order_id} not found")
        if order.status not in ('DRAFT', 'WAITING_APPROVAL'):
            raise AccountsValidationError("Only DRAFT or WAITING_APPROVAL orders can be cancelled")
        order.status = 'CANCELLED'
        order.cancelled_by_id = employee.id
        order.cancelled_at = get_indian_time()
        order.updated_at = get_indian_time()
        db.commit()
        db.refresh(order)
        return order

    @staticmethod
    def get_purchase_prefill(
        db: Session, employee: StaffEmployee,
        order_id: int, vendor_id: int
    ) -> Dict:
        """
        Returns a VendorTransactionCreate-compatible payload pre-filled
        from the approved spare order lines for the given vendor.
        Used by 'Convert to Purchase' button.
        """
        from app.models.staff_accounts import SparePurchaseOrder, SparePurchaseOrderLine, VendorMaster
        validate_accounts_read_access(employee)
        order = db.query(SparePurchaseOrder).filter(SparePurchaseOrder.id == order_id).first()
        if not order:
            raise AccountsNotFoundError(f"Spare order {order_id} not found")

        vendor = db.query(VendorMaster).filter(VendorMaster.id == vendor_id).first()
        lines = [l for l in order.lines if l.vendor_id == vendor_id]

        return {
            'company_id':     order.company_id,
            'vendor_id':      vendor_id,
            'vendor_name':    vendor.vendor_name if vendor else None,
            'vendor_code':    vendor.vendor_code if vendor else None,
            'transaction_type': 'PURCHASE',
            'record_type':    'PRODUCT',
            'invoice_status': 'NOT_RECEIVED',
            'narration':      f"Purchase against Spare PO {order.order_number}",
            'spare_order_id': order_id,
            'spare_order_number': order.order_number,
            'line_items': [
                {
                    'item_id':          l.item_id,
                    'item_code':        l.item_code,
                    'item_description': l.item_name or l.item_code,
                    'quantity':         float(l.quantity),
                    'unit_of_measure':  l.unit_of_measure,
                    'unit_rate':        float(l.last_purchase_rate) if l.last_purchase_rate else 0,
                    'gst_rate':         0,
                    'discount_percent': 0,
                }
                for l in lines
            ]
        }

    # ── partner spare request CRUD ────────────────────────────────────────────

    @staticmethod
    def partner_get_spare_catalog(
        db: Session,
        partner_id: int,
        company_id: Optional[int] = None,
        search: Optional[str] = None,
        skip: int = 0, limit: int = 100
    ) -> Tuple[List[Dict], int]:
        """Spare catalog visible to partner: all active SPARE_PART items with stock."""
        q = db.query(StockItemMaster).filter(
            StockItemMaster.is_active == True,
            StockItemMaster.item_category == 'SPARE_PART',
        )
        if search:
            q = q.filter(or_(
                StockItemMaster.item_code.ilike(f"%{search}%"),
                StockItemMaster.item_name.ilike(f"%{search}%"),
            ))
        total = q.count()
        items = q.order_by(StockItemMaster.item_code).offset(skip).limit(limit).all()
        item_ids = [i.id for i in items]
        if not item_ids:
            return [], total

        stock_rows = db.execute(text("""
            SELECT item_id, SUM(quantity_in - quantity_out)
            FROM stock_ledger
            WHERE item_id = ANY(:ids)
              """ + (f"AND company_id = {company_id}" if company_id else "") + """
            GROUP BY item_id
        """), {'ids': item_ids}).fetchall()
        stock_map = {r[0]: float(r[1] or 0) for r in stock_rows}

        return [
            {
                'item_id':        i.id,
                'item_code':      i.item_code,
                'item_name':      i.item_name,
                'unit_of_measure': i.unit_of_measure or 'PCS',
                'hsn_code':       i.hsn_code,
                'purchase_rate':  float(i.purchase_rate or 0),
                'current_stock':  stock_map.get(i.id, 0),
                'in_stock':       stock_map.get(i.id, 0) > 0,
            }
            for i in items
        ], total

    @staticmethod
    def partner_submit_spare_request(
        db: Session,
        partner_id: int,
        company_id: int,
        items: List[Dict],   # [{item_id, quantity, uom, notes}]
        notes: str = None,
    ):
        from app.models.staff_accounts import (
            PartnerSpareRequest, PartnerSpareRequestLine, StockItemMaster
        )
        if not items:
            raise AccountsValidationError("At least one item is required")

        req = PartnerSpareRequest(
            request_number=SpareProcurementService._gen_request_number(db),
            partner_id=partner_id,
            company_id=company_id,
            status='SUBMITTED',
            notes=notes,
        )
        db.add(req)
        db.flush()

        for it in items:
            item = db.query(StockItemMaster).filter(StockItemMaster.id == it['item_id']).first()
            line = PartnerSpareRequestLine(
                request_id=req.id,
                item_id=it['item_id'],
                item_code=item.item_code if item else None,
                item_name=item.item_name if item else None,
                quantity=Decimal(str(it.get('quantity', 1))),
                unit_of_measure=it.get('uom') or (item.unit_of_measure if item else 'PCS'),
                notes=it.get('notes'),
            )
            db.add(line)

        db.commit()
        db.refresh(req)
        return req

